// === Shorts Blocker: Hide shorts, reorder sidebar, manage CSS ===

function injectShortsBlockerCSS() {
    if (!document.getElementById(SHORTS_BLOCKER_CSS_ID)) {
        const style = document.createElement('style');
        style.id = SHORTS_BLOCKER_CSS_ID;
        style.textContent = SHORTS_BLOCKER_CSS;
        (document.head || document.documentElement).appendChild(style);
    }
}

function removeShortsBlockerCSS() {
    const el = document.getElementById(SHORTS_BLOCKER_CSS_ID);
    if (el) el.remove();
}

function applyShortsBlockerState() {
    if (shortsBlockerSettings.enabled) {
        injectShortsBlockerCSS();
        blockShorts();
    } else {
        removeShortsBlockerCSS();
        removeMockingScreen();
        // Un-hide any JS-hidden shorts tabs
        unhideShortsTabs();
    }
}

function unhideShortsTabs() {
    const selectors = ['yt-tab-shape', 'tp-yt-paper-tab', '.yt-tab-shape-wiz__tab', 'yt-chip-cloud-chip-renderer'];
    selectors.forEach(selector => {
        const elements = document.querySelectorAll(selector);
        elements.forEach(el => {
            const text = el.textContent.trim().toLowerCase();
            const aria = (el.getAttribute('aria-label') || '').toLowerCase();
            const title = (el.getAttribute('tab-title') || '').toLowerCase();
            if (text === 'shorts' || aria === 'shorts' || title === 'shorts') {
                el.style.removeProperty('display');
            }
        });
    });
}

function blockShorts() {
    // Hide channel tabs using JS (more reliable than CSS for text matching)
    hideShortsTabs();
    
    // Remove entire Shorts shelves/sections (including headers and "Show more" buttons)
    hideShortsShelves();

    // Reorder sidebar as requested
    reorderSidebar();

    // Check if we are on a shorts page
    if (window.location.pathname.startsWith('/shorts/')) {
        injectMockingScreen();
    } else {
        removeMockingScreen();
    }
}

function reorderSidebar() {
    // Find the sections by targeting the links they contain
    // "Subscriptions" corresponds to /feed/subscriptions
    // "You" corresponds to /feed/you or /feed/library
    const subLink = document.querySelector('a[href="/feed/subscriptions"]');
    const youLink = document.querySelector('a[href="/feed/you"], a[href="/feed/library"]');

    if (subLink && youLink) {
        const subSection = subLink.closest('ytd-guide-section-renderer');
        const youSection = youLink.closest('ytd-guide-section-renderer');

        if (subSection && youSection && subSection.parentNode === youSection.parentNode) {
            const parent = subSection.parentNode;
            // Check if youSection is after subSection in the DOM
            if (subSection.compareDocumentPosition(youSection) & Node.DOCUMENT_POSITION_FOLLOWING) {
                // Move youSection before subSection
                parent.insertBefore(youSection, subSection);
            }
        }
    }
}

function hideShortsTabs() {
    const selectors = ['yt-tab-shape', 'tp-yt-paper-tab', '.yt-tab-shape-wiz__tab', 'yt-chip-cloud-chip-renderer'];
    selectors.forEach(selector => {
        const elements = document.querySelectorAll(selector);
        elements.forEach(el => {
            const text = el.textContent.trim().toLowerCase();
            const aria = (el.getAttribute('aria-label') || '').toLowerCase();
            const title = (el.getAttribute('tab-title') || '').toLowerCase();
            
            if (text === 'shorts' || aria === 'shorts' || title === 'shorts' || (el.querySelector && el.querySelector('a[href*="/shorts"]'))) {
                el.style.setProperty('display', 'none', 'important');
            }
        });
    });

    // Also hide any link that goes to shorts directly
    const links = document.querySelectorAll('a[href*="/shorts"]');
    links.forEach(link => {
        // If it's a tab link, hide the parent/containier if needed, but mostly the link itself
        if (link.classList.contains('yt-tab-shape-wiz__tab') || link.closest('tp-yt-paper-tab')) {
             const tab = link.closest('yt-tab-shape') || link.closest('tp-yt-paper-tab') || link;
             tab.style.setProperty('display', 'none', 'important');
        }
    });
}

function hideShortsShelves() {
    // 1. Find by the specific class identified in the screenshot
    const gridHosts = document.querySelectorAll('.ytGridShelfViewModelHost');
    gridHosts.forEach(host => {
        // If it contains a shorts link or the Shorts icon, hide the whole host
        if (host.querySelector('a[href*="/shorts/"]') || host.querySelector('yt-icon[type="shorts"]')) {
            if (host.style.display !== 'none') {
                host.style.setProperty('display', 'none', 'important');
            }
        }
    });

    // 2. Find by Shorts Icon (more generic)
    const shortsIcons = document.querySelectorAll('yt-icon[type="shorts"], path[d*="M17.7,3"]');
    shortsIcons.forEach(icon => {
        const shelf = icon.closest('ytd-shelf-renderer, ytd-rich-shelf-renderer, ytd-reel-shelf-renderer, ytd-rich-section-renderer, .ytGridShelfViewModelHost');
        if (shelf && shelf.style.display !== 'none') {
            shelf.style.setProperty('display', 'none', 'important');
        }
    });

    // 3. Find by Header Text "Shorts"
    const titles = document.querySelectorAll('h2#title, span#title, #title-text');
    titles.forEach(h => {
        if (h.textContent.trim().toLowerCase() === 'shorts') {
             const shelf = h.closest('ytd-shelf-renderer, ytd-rich-shelf-renderer, ytd-reel-shelf-renderer, ytd-rich-section-renderer, .ytGridShelfViewModelHost');
             if (shelf && shelf.style.display !== 'none') {
                  shelf.style.setProperty('display', 'none', 'important');
             }
        }
    });
}


// ─── shorts-blocker/mocking-screen.js ──────────────────────────── 
// === Mocking Screen: Overlay when user navigates to /shorts/ ===

function removeMockingScreen() {
    const overlay = document.getElementById('shorts-blocker-overlay');
    if (overlay) {
        // Clear the playback killer interval
        const intervalId = overlay.dataset.playbackIntervalId;
        if (intervalId) {
            clearInterval(Number(intervalId));
        }
        overlay.remove();
    }
}

function injectMockingScreen() {
    if (document.getElementById('shorts-blocker-overlay')) return;

    const overlay = document.createElement('div');
    overlay.id = 'shorts-blocker-overlay';
    overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        width: 100vw;
        height: 100vh;
        background: radial-gradient(circle at center, #1b1b1b 0%, #050505 100%);
        color: white;
        display: flex;
        justify-content: center;
        align-items: center;
        z-index: 2147483647;
        font-family: 'Inter', 'Roboto', Arial, sans-serif;
        text-align: center;
        overflow: hidden;
    `;

    overlay.innerHTML = `
        <div id="civilization-card" style="
            background: rgba(255, 255, 255, 0.03);
            backdrop-filter: blur(40px) saturate(150%);
            -webkit-backdrop-filter: blur(40px) saturate(150%);
            border: 1px solid rgba(255, 255, 255, 0.1);
            padding: 64px 48px;
            border-radius: 40px;
            box-shadow: 0 40px 100px rgba(0, 0, 0, 0.8), inset 0 0 0 1px rgba(255, 255, 255, 0.05);
            max-width: 600px;
            width: 90%;
            display: flex;
            flex-direction: column;
            align-items: center;
            opacity: 0;
            transform: translateY(40px);
            transition: all 0.8s cubic-bezier(0.2, 0.8, 0.2, 1);
        ">
            <div style="margin-bottom: 40px; animation: ytt-float 4s infinite ease-in-out;">
                <svg width="100" height="70" viewBox="0 0 1024 721" xmlns="http://www.w3.org/2000/svg">
                    <path fill="#FF0000" d="M1013 156c-12-44-47-79-92-91C841 40 512 40 512 40s-329 0-409 25c-45 12-80 47-92 91C-13 237-13 404-13 404s0 167 24 248c12 44 47 80 92 92 80 24 409 24 409 24s329 0 409-24c45-12 80-48 92-92 24-81 24-248 24-248s0-167-24-248z"/>
                    <polygon fill="#FFF" points="408 528 674 404 408 280"/>
                </svg>
            </div>
            
            <h1 style="font-size: 48px; font-weight: 900; margin: 0 0 16px; letter-spacing: -2px; color: #fff; line-height: 1.1;">Shorts Blocked</h1>
            <p style="font-size: 18px; color: rgba(255, 255, 255, 0.6); margin-bottom: 48px; line-height: 1.6; font-weight: 500;">
                Focus on what matters. Your concentration is valuable, <br>
                and today is a great day to be <span style="color: #FF0033; font-weight: 700;">productive</span>.
            </p>
            
            <button id="go-back-btn" class="modal-btn premium-primary" style="width: 240px; height: 56px; font-size: 16px; text-transform: none;">
                Back to Civilization
            </button>
        </div>

        <style>
            @keyframes ytt-float {
                0%, 100% { transform: translateY(0) rotate(0deg); }
                33% { transform: translateY(-15px) rotate(2deg); }
                66% { transform: translateY(-5px) rotate(-1deg); }
            }
            #shorts-blocker-overlay::before {
                content: '';
                position: absolute;
                top: 50%;
                left: 50%;
                width: 600px;
                height: 600px;
                background: radial-gradient(circle, rgba(255, 0, 51, 0.08) 0%, transparent 70%);
                transform: translate(-50%, -50%);
                pointer-events: none;
                z-index: -1;
            }
        </style>
    `;

    document.documentElement.appendChild(overlay);

    // Staggered Entrance Animation
    requestAnimationFrame(() => {
        const card = document.getElementById('civilization-card');
        if (card) {
            card.style.opacity = '1';
            card.style.transform = 'translateY(0)';
        }
    });

    document.getElementById('go-back-btn').onclick = (e) => {
        e.preventDefault();
        window.location.href = 'https://www.youtube.com';
    };

    // Kill playback
    const killPlayback = () => {
        const media = document.querySelectorAll('video, audio');
        media.forEach(m => {
            m.pause();
            m.muted = true;
            m.volume = 0;
            m.currentTime = 0;
            m.style.display = 'none';
        });
    };
    
    killPlayback();
    const playbackInterval = setInterval(killPlayback, 100);
    overlay.dataset.playbackIntervalId = playbackInterval;
}


// ─── stats-tracker/tracking.js ─────────────────────────────────── 
// === Stats Tracking: Video watch time recording ===

/**
 * @param {string|undefined} explicitVideoId - Force a specific video ID (used during navigation).
 * @param {boolean} isFinalSync - If true, don't read from the video element (it may already
 *   be reset by YouTube's SPA navigation). Use cached values from the last normal tick instead.
 */
function updateStats(explicitVideoId, isFinalSync) {
  if (window.yttContextInvalidated) return;

  const now = Date.now();
  const delta = (now - lastWatchTimeUpdate) / 1000;
  lastWatchTimeUpdate = now;

  const watchFlexy = document.querySelector("ytd-watch-flexy");
  let videoId =
    explicitVideoId ||
    (watchFlexy
      ? watchFlexy.getAttribute("video-id")
      : new URLSearchParams(window.location.search).get("v"));

  const video =
    document.querySelector("video.video-stream.html5-main-video") ||
    document.querySelector("video");

  // Skip tracking during YouTube ads
  const isAd = !!document.querySelector(
    ".ad-showing, .ad-interrupting, .ytp-ad-player-overlay",
  );
  if (isAd) return;

  // Ensure we have a bucket for today
  const currentDay = getDayKey();
  if (!allHistory[currentDay]) {
    allHistory[currentDay] = { watchTime: 0, videos: [], sessionStart: now };
  }
  const todayData = allHistory[currentDay];
  const isNewVideo = videoId !== lastVideoId;

  if (videoId) {
    currentUid = `${currentDay}_${videoId}`;

    // Skip tracking for videos the user explicitly deleted
    if (deletedUids.has(currentUid)) {
      // Still send a heartbeat even if this specific video is blacklisted
      safeSendMessage({ action: 'REPORT_WATCH_TIME', delta });
      return;
    }

    if (isNewVideo || !todayData.videos.find((v) => v.uid === currentUid)) {
      if (isNewVideo) {
        lastVideoId = videoId;
        // New video loaded — old deletions no longer relevant
        deletedUids.clear();
      }

      const videoTitleEl =
        document.querySelector("h1.ytd-watch-metadata") ||
        document.querySelector(".ytd-video-primary-info-renderer h1.title");
      const title = videoTitleEl
        ? videoTitleEl.textContent.trim()
        : "Loading Video...";

      const channelNameEl =
        document.querySelector("#upload-info #channel-name a") ||
        document.querySelector("ytd-video-owner-renderer #channel-name a");
      const channelName = channelNameEl
        ? channelNameEl.textContent.trim()
        : "Loading Channel...";

      const channelAvatarEl = 
        document.querySelector("ytd-video-owner-renderer #avatar yt-img-shadow img") ||
        document.querySelector("ytd-watch-metadata #owner #avatar img") ||
        document.querySelector("#owner #avatar img") ||
        document.querySelector("ytd-video-owner-renderer img") ||
        document.querySelector("#upload-info img#img");
      const channelThumb = channelAvatarEl ? (channelAvatarEl.currentSrc || channelAvatarEl.src) : null;

      if (!todayData.videos.find((v) => v.uid === currentUid)) {
        todayData.videos.push({
          uid: currentUid,
          id: videoId,
          title: title,
          channelName: channelName,
          thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`,
          channelThumb: channelThumb,
          startTime: new Date().toLocaleTimeString(),
          watchedDuration: 0,
          currentPosition: 0,
          // Don't read duration from video element here — it might still
          // hold the previous video's duration (YouTube reuses the element).
          // Subsequent normal ticks will populate this correctly.
          totalDuration: 0,
        });
      }
    }

    const activeVideo = todayData.videos.find((v) => v.uid === currentUid);

    // --- FINAL SYNC PATH ---
    // During navigation/unload, YouTube may have already reset the <video> element.
    // Don't read from it — just send whatever we last cached on activeVideo.
    if (isFinalSync && activeVideo) {
      safeSendMessage({
        action: "REPORT_WATCH_TIME",
        delta: 0,
        videoId: videoId,
        videoTitle: activeVideo.title,
        channelName: activeVideo.channelName,
        currentPosition: activeVideo.currentPosition || 0,
        totalDuration: activeVideo.totalDuration || 0,
      });
      return;
    }

    // --- NORMAL TRACKING PATH ---
    if (activeVideo && video) {
      // Lazy-load title and channel
      if (activeVideo.title === "Loading Video...") {
        const videoTitleEl =
          document.querySelector("h1.ytd-watch-metadata") ||
          document.querySelector(".ytd-video-primary-info-renderer h1.title");
        if (videoTitleEl) activeVideo.title = videoTitleEl.textContent.trim();
      }
      if (activeVideo.channelName === "Loading Channel...") {
        const channelNameEl =
          document.querySelector("#upload-info #channel-name a") ||
          document.querySelector("ytd-video-owner-renderer #channel-name a");
        if (channelNameEl)
          activeVideo.channelName = channelNameEl.textContent.trim();
      }
      if (!activeVideo.channelThumb || activeVideo.channelThumb.startsWith('data:')) {
        const channelAvatarEl = 
          document.querySelector("ytd-video-owner-renderer #avatar yt-img-shadow img") ||
          document.querySelector("ytd-watch-metadata #owner #avatar img") ||
          document.querySelector("#owner #avatar img") ||
          document.querySelector("ytd-video-owner-renderer img") ||
          document.querySelector("#upload-info img#img");
        if (channelAvatarEl) {
          const src = channelAvatarEl.currentSrc || channelAvatarEl.src;
          if (src && !src.startsWith('data:')) {
            activeVideo.channelThumb = src;
          }
        }
      }

      // GUARD: When isNewVideo is true, skip reading from the <video> element.
      // YouTube reuses the same element, so it may still hold the OLD video's
      // currentTime and duration. Wait for the next tick when the element is stable.
      if (!isNewVideo) {
        const liveDuration =
          isFinite(video.duration) && video.duration > 0 ? video.duration : 0;
        const liveTime = isFinite(video.currentTime) ? video.currentTime : 0;

        // --- TRANSITION GUARD ---
        // If duration changes significantly (>2s) for the same video ID,
        // or if time jumps back to near-zero while it was previously near the end,
        // it means YouTube has auto-played the next video but hasn't updated the ID yet.
        // In these cases, we SKIP updating the old video's metadata.

        const isNearEnd =
          activeVideo.totalDuration > 0 &&
          activeVideo.totalDuration - activeVideo.currentPosition < 5;
        const suddenJumpToStart = isNearEnd && liveTime < 2 && !video.paused;
        const durationMismatch =
          activeVideo.totalDuration > 0 &&
          liveDuration > 0 &&
          Math.abs(activeVideo.totalDuration - liveDuration) > 1;

        if (suddenJumpToStart || durationMismatch) {
          // Transition detected: don't pollute OLD video entry with NEW video data
          return;
        }

        // Update totalDuration when a valid value is available
        if (liveDuration > 0) {
          activeVideo.totalDuration = liveDuration;
        }

        // Update current position from the live video element
        if (liveTime > 0 || activeVideo.currentPosition === 0) {
          activeVideo.currentPosition = liveTime;
        }
      }

      // Report time and video state to background for atomic update
      const isPlaying =
        !isNewVideo && !video.paused && !video.ended && video.readyState >= 2;
      safeSendMessage(
        {
          action: "REPORT_WATCH_TIME",
          delta: isPlaying ? delta : 0,
          isPlaying: isPlaying,
          videoId: videoId,
          videoTitle: activeVideo.title,
          channelName: activeVideo.channelName,
          currentPosition: activeVideo.currentPosition || 0,
          totalDuration: activeVideo.totalDuration || 0,
        },
        (response) => {
          if (response && response.otherPlayingTabId && isPlaying) {
            // Only show if we aren't currently showing it, and sidebar is closed
            if (!window.multiTabToastShown && !isStatsOpen) {
              window.multiTabToastShown = true;
              showMultiTabToast(response.otherPlayingTabId, () => {
                // Reset flag after a while so it doesn't stay blocked forever
                setTimeout(() => {
                  window.multiTabToastShown = false;
                }, 5000);
              });
            }
          }
        },
      );
    }
  } else {
    // Heartbeat for non-video pages (Home, Subscriptions, etc.) to track active session time
    safeSendMessage({ action: "REPORT_WATCH_TIME", delta });
  }

  if (isStatsOpen) {
    renderStats();
  }
}


