// ─── stats-tracker/sidebar-events.js ───────────────────────────── 
// === Sidebar Event Bindings: Filters, navigation, settings, open/close ===

/**
 * Global view switcher accessible from all modules
 */
let viewHistory = ["history"]; // Navigation stack
let selectedChannelForVideos = null; // Currently viewed channel's videos
let isFilterCollapsed = true; // Track requested manual state of the date picker/filters slider

/**
 * Synchronizes all UI controls (toggles, inputs, dropdowns) with the current
 * in-memory global state variables. Used for instant updates after backup restores.
 */
function syncSettingsUI() {
  // 0. Syncing based on current selectedDayFilter (no forced reset to 'today' here)

  // 1. Toggles
  const shortsToggle = document.getElementById("shorts-blocker-toggle");
  if (shortsToggle) shortsToggle.checked = shortsBlockerSettings.enabled;

  const dislikeToggle = document.getElementById("dislike-count-toggle");
  if (dislikeToggle) dislikeToggle.checked = dislikeCountSettings.enabled;

  const breakToggle = document.getElementById("break-enabled-toggle");
  if (breakToggle) breakToggle.checked = breakSettings.enabled;

  const backupEnabledToggle = document.getElementById("backup-enabled-toggle");
  if (backupEnabledToggle) backupEnabledToggle.checked = backupSettings.enabled;

  const backupOnCloseToggle = document.getElementById("backup-on-close-toggle");
  if (backupOnCloseToggle)
    backupOnCloseToggle.checked = backupSettings.backupOnClose;

  const backupReminderToggle = document.getElementById("backup-reminder-toggle");
  if (backupReminderToggle)
    backupReminderToggle.checked = backupSettings.reminderEnabled;

  const reminderContainer = document.getElementById("reminder-interval-container");
  if (reminderContainer)
    reminderContainer.style.display = backupSettings.reminderEnabled ? "flex" : "none";

  const smartFullscreenToggle = document.getElementById("smart-fullscreen-toggle");
  if (smartFullscreenToggle)
    smartFullscreenToggle.checked = smartFullscreenSettings.enabled;

  const opacityToggle = document.getElementById("opacity-enabled-toggle");
  if (opacityToggle) opacityToggle.checked = opacitySettings.enabled;

  const opacitySlider = document.getElementById("opacity-value-slider");
  if (opacitySlider) {
    opacitySlider.value = opacitySettings.value;
    updateSliderProgress(opacitySlider);
  }

  const opacityLabel = document.getElementById("opacity-percentage-label");
  if (opacityLabel) opacityLabel.textContent = Math.round(opacitySettings.value * 100) + "%";

  const opacitySliderContainer = document.getElementById("opacity-slider-container");
  if (opacitySliderContainer) opacitySliderContainer.style.display = opacitySettings.enabled ? "flex" : "none";

  // 2. Numeric & Text Inputs
  const intervalValue = document.getElementById("interval-value");
  if (intervalValue && document.activeElement !== intervalValue) {
    intervalValue.value = breakSettings.intervalValue;
  }

  const workUrlInput = document.getElementById("setting-work-url");
  if (workUrlInput && document.activeElement !== workUrlInput) {
    workUrlInput.value = breakSettings.workUrl;
  }

  const maxBackupsValue = document.getElementById("max-backups-value");
  if (maxBackupsValue && document.activeElement !== maxBackupsValue) {
    maxBackupsValue.value = backupSettings.maxBackups || 10;
  }

  const reminderValueInput = document.getElementById("reminder-interval-value");
  if (reminderValueInput && document.activeElement !== reminderValueInput) {
    if (backupSettings.reminderInterval !== undefined) {
      reminderValueInput.value = backupSettings.reminderInterval;
    }
  }

  // 3. Custom Dropdowns
  const syncDropdown = (id, value, map) => {
    const dropdown = document.getElementById(id);
    if (!dropdown) return;
    dropdown.dataset.value = value;
    const triggerSpan = dropdown.querySelector(".dropdown-trigger span");
    if (triggerSpan) {
      const defaultLabels = {
        minutes: "min",
        seconds: "sec",
        hours: "hr",
      };
      // Prioritize explicit map > default labels > raw value
      triggerSpan.textContent = (map && map[value]) || defaultLabels[value] || value;
    }

    const items = dropdown.querySelectorAll(".dropdown-item");
    items.forEach((item) => {
      item.classList.toggle(
        "active",
        String(item.dataset.value) === String(value),
      );
    });
  };

  syncDropdown("backup-interval-dropdown", backupSettings.intervalHours, {
    1: "Every Hour",
    6: "Every 6 Hours",
    12: "Every 12 Hours",
    24: "Every Day",
    168: "Every Week",
  });

  syncDropdown("reminder-interval-unit-dropdown", backupSettings.reminderUnit, {
    weeks: "wks",
    days: "days",
    hours: "hr",
    minutes: "min",
    seconds: "sec",
  });

  syncDropdown("retention-duration-dropdown", retentionSettings.duration, {
    7: "7 Days",
    15: "15 Days",
    30: "30 Days",
    90: "3 Months",
    180: "6 Months",
    365: "1 Year",
    "-1": "Unlimited",
  });

  syncDropdown("history-period-dropdown", selectedDayFilter, {});

  syncDropdown("interval-unit-dropdown", breakSettings.intervalUnit, {
    minutes: "min",
    seconds: "sec",
    hours: "hr",
  });

  // 4. Special internal UI syncs
  if (typeof syncHistoryPresets === "function") syncHistoryPresets();
  if (typeof updateDateLabel === "function") updateDateLabel();
}

/**
 * Formats a date or preset label for the UI (e.g., "Apr 7, 2026", "Today", or "Last 30 Days").
 */
const formatDateLabel = (value) => {
  const map = {
    today: "Today",
    yesterday: "Yesterday",
    "7days": "Last 7 Days",
    "15days": "Last 15 Days",
    "30days": "Last 30 Days",
    "90days": "Last 3 Months",
    "180days": "Last 6 Months",
    "365days": "Last Year",
    all: "All Time",
  };

  if (map[value]) return map[value];

  // Check if it's a specific date YYYY-MM-DD
  const parts = String(value).split("-").map(Number);
  if (parts.length === 3 && !parts.some(isNaN)) {
    const d = new Date(parts[0], parts[1] - 1, parts[2]);
    return d.toLocaleDateString(undefined, {
      month: "short",
      day: "numeric",
      year: "numeric",
    });
  }

  if (String(value).endsWith("days")) {
    return `Last ${parseInt(value, 10)} Days`;
  }

  return value;
};

/**
 * Updates the current date label in the history view and synchronizes the period dropdown.
 */
const updateDateLabel = () => {
  const formatted = formatDateLabel(selectedDayFilter);

  // 1. Update side navigation label
  const sideLabel = document.querySelector(".current-date-label");
  if (sideLabel) sideLabel.textContent = formatted;

  // 2. Update period dropdown trigger text
  const histDropdown = document.getElementById("history-period-dropdown");
  if (histDropdown) {
    histDropdown.dataset.value = selectedDayFilter;
    const triggerSpan = histDropdown.querySelector(".dropdown-trigger span");
    if (triggerSpan) {
      // Mapping for dropdown specific labels (e.g. "All History" instead of "All Time")
      const dropdownLabels = { all: "All History" };
      triggerSpan.textContent = dropdownLabels[selectedDayFilter] || formatted;
    }

    // Update active class on items
    const items = histDropdown.querySelectorAll(".dropdown-item");
    items.forEach((item) => {
      item.classList.toggle(
        "active",
        String(item.dataset.value) === String(selectedDayFilter),
      );
    });
  }
};

/**
 * Syncs the history period dropdown items with data retention settings.
 */
const syncHistoryPresets = () => {
  const dropdown = document.getElementById("history-period-dropdown");
  if (!dropdown) return;

  const duration = retentionSettings.duration;
  const items = dropdown.querySelectorAll(".dropdown-item");

  items.forEach((item) => {
    const val = item.dataset.value;
    if (val === "today" || val === "yesterday" || val === "all") {
      item.style.display = "block";
      return;
    }

    const days = parseInt(val, 10);
    if (duration === -1 || days <= duration) {
      item.style.display = "block";
    } else {
      item.style.display = "none";
    }
  });

  // Update Special chip label
  const specialItem = dropdown.querySelector(".dropdown-item.special");
  if (specialItem) {
    specialItem.textContent =
      duration === -1 ? "Unlimited History" : duration + " Days History";
  }
};

function switchView(viewName) {
  if (viewName !== activeView) {
    viewHistory.push(viewName);
    // Keep stack manageable
    if (viewHistory.length > 20) viewHistory.shift();
  }
  _switchViewInternal(viewName);
}

function _switchViewInternal(viewName) {
  activeView = viewName;
  const hView = document.getElementById("history-view");
  const aView = document.getElementById("analytics-view");
  const sView = document.getElementById("settings-view");
  const hFilters = document.getElementById("stats-header-filters");

  if (hView) hView.style.display = viewName === "history" ? "block" : "none";
  if (aView) aView.style.display = viewName === "analytics" ? "block" : "none";
  if (sView) sView.style.display = viewName === "settings" ? "block" : "none";
  if (hFilters) hFilters.style.display = "block";

  const toggleStrip = document.getElementById("history-filter-toggle");
  if (toggleStrip) toggleStrip.style.display = "flex";

  const bView = document.getElementById("backup-view");
  if (bView) bView.style.display = viewName === "backup" ? "block" : "none";

  const cdView = document.getElementById("channel-distribution-view");
  if (cdView)
    cdView.style.display =
      viewName === "channel-distribution" ? "block" : "none";

  const cvView = document.getElementById("channel-videos-view");
  if (cvView)
    cvView.style.display = viewName === "channel-videos" ? "block" : "none";

  const kbView = document.getElementById("keybinds-view");
  const historyContent = document.getElementById("history-header-content");

  if (kbView) {
    kbView.style.display = viewName === "keybinds" ? "block" : "none";
    if (viewName === "keybinds" || viewName === "history" || viewName === "analytics") {
      if (viewName === "keybinds" && typeof renderKeybinds === "function") renderKeybinds();
      if (historyContent) historyContent.style.display = "flex";
      if (hFilters) {
        hFilters.style.display = "block";
        hFilters.classList.toggle("collapsed", isFilterCollapsed);
        const tBtn = document.getElementById("toggle-filter-btn");
        if (tBtn) {
          tBtn.classList.toggle("expanded", !isFilterCollapsed);
          tBtn.innerHTML = isFilterCollapsed ? icons.chevron_down : icons.chevron_up;
        }
      }
    } else {
      if (hFilters) hFilters.classList.add("collapsed");
    }
  }

  const cPopover = document.getElementById("calendar-popover");
  if (cPopover) cPopover.style.display = "none";

  // Update universal view title bar
  const viewTitleMap = {
    history: "Watch History",
    analytics: "Analytics",
    "channel-distribution": "Channel Distribution",
    "channel-videos": "Channel Activity",
    backup: "Backup & Restore",
    settings: "Settings",
    keybinds: "Keybinds"
  };
  const titleText = document.getElementById("view-title-text");
  const backBtn = document.getElementById("view-back-btn");
  if (titleText) titleText.textContent = viewTitleMap[viewName] || viewName;
  if (backBtn) {
    // Always show back button per user request
    backBtn.style.display = "flex";

    // Update opacity to indicate if there's history to walk back into
    backBtn.style.opacity = viewHistory.length > 1 ? "1" : "0.5";

    backBtn.onclick = (e) => {
      e.stopPropagation();
      // Pop the current view off the stack
      if (viewHistory.length > 1) {
        viewHistory.pop(); // remove current
        const prev = viewHistory[viewHistory.length - 1];
        _switchViewInternal(prev);
      } else {
        // If on root, ensure we stay on history or perform a subtle UI feedback
        // Providing a consistent "Back" experience as requested
        _switchViewInternal("history");
      }
    };
  }

  // Update Button Active States
  ["nav-history", "nav-analytics", "nav-backup", "nav-settings"].forEach(
    (id) => {
      const navBtn = document.getElementById(id);
      if (navBtn) navBtn.classList.toggle("active", id === `nav-${viewName}`);
    },
  );

  if (typeof renderStats === "function") renderStats();
}

function bindSidebarEvents(sidebar, btn, dragStatus) {
  // Date Navigator & Calendar Logic
  let calendarDate = new Date(); // Month/Year currently shown in the calendar popover

  // Handled by top-level updateDateLabel()

  const renderCalendar = () => {
    const container = document.getElementById("calendar-popover");
    if (!container) return;

    const year = calendarDate.getFullYear();
    const month = calendarDate.getMonth();
    const monthName = new Date(year, month).toLocaleString(undefined, {
      month: "long",
    });

    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const todayStr = getDayKey(new Date());
    const selectedStr =
      selectedDayFilter === "today"
        ? todayStr
        : selectedDayFilter === "yesterday"
          ? getDayKey(new Date(Date.now() - 86400000))
          : selectedDayFilter;

    let html = `
      <div class="calendar-header">
        <div class="calendar-month-year">${monthName} ${year}</div>
        <div class="calendar-nav">
          <button id="cal-prev" class="nav-arrow-btn">${icons.prev}</button>
          <button id="cal-next" class="nav-arrow-btn">${icons.next}</button>
        </div>
      </div>
      <div class="calendar-grid">
        <div class="calendar-day-label">Su</div>
        <div class="calendar-day-label">Mo</div>
        <div class="calendar-day-label">Tu</div>
        <div class="calendar-day-label">We</div>
        <div class="calendar-day-label">Th</div>
        <div class="calendar-day-label">Fr</div>
        <div class="calendar-day-label">Sa</div>
    `;

    // Empty slots before first day
    for (let i = 0; i < firstDay; i++) {
      html += '<div class="calendar-day empty"></div>';
    }

    // Days of month
    for (let d = 1; d <= daysInMonth; d++) {
      const dateKey = `${year}-${String(month + 1).padStart(2, "0")}-${String(
        d,
      ).padStart(2, "0")}`;
      const isToday = dateKey === todayStr;
      const isSelected = dateKey === selectedStr;

      html += `
        <div class="calendar-day ${isToday ? "today" : ""} ${
          isSelected ? "selected" : ""
        }" data-date="${dateKey}">
          ${d}
        </div>
      `;
    }

    html += "</div>";
    container.innerHTML = html;

    // Calendar Handlers
    container.querySelector("#cal-prev").onclick = (e) => {
      e.stopPropagation();
      calendarDate.setMonth(calendarDate.getMonth() - 1);
      renderCalendar();
    };
    container.querySelector("#cal-next").onclick = (e) => {
      e.stopPropagation();
      calendarDate.setMonth(calendarDate.getMonth() + 1);
      renderCalendar();
    };
    container.querySelectorAll(".calendar-day:not(.empty)").forEach((el) => {
      el.onclick = (e) => {
        e.stopPropagation();
        selectedDayFilter =
          el.dataset.date === todayStr ? "today" : el.dataset.date;
        container.style.display = "none";
        updateDateLabel();
        renderStats();
      };
    });
  };

  const trigger = document.getElementById("calendar-trigger");
  const popover = document.getElementById("calendar-popover");
  if (trigger && popover) {
    trigger.onclick = (e) => {
      e.stopPropagation();
      const isVisible = popover.style.display === "block";
      popover.style.display = isVisible ? "none" : "block";
      if (!isVisible) renderCalendar();
    };
  }

  const prevBtn = document.getElementById("date-prev");
  const nextBtn = document.getElementById("date-next");

  const shiftDate = (offset) => {
    let current;
    if (selectedDayFilter === "today") {
      current = new Date();
    } else if (selectedDayFilter === "yesterday") {
      current = new Date(Date.now() - 86400000);
    } else if (
      selectedDayFilter === "all" ||
      selectedDayFilter.endsWith("days")
    ) {
      current = new Date();
    } else {
      const parts = selectedDayFilter.split("-").map(Number);
      if (parts.length === 3 && !parts.some(isNaN)) {
        current = new Date(parts[0], parts[1] - 1, parts[2]);
      } else {
        current = new Date();
      }
    }
    current.setDate(current.getDate() + offset);

    const newKey = getDayKey(current);
    selectedDayFilter = newKey === getDayKey(new Date()) ? "today" : newKey;
    updateDateLabel();
    renderStats();
  };

  if (prevBtn)
    prevBtn.onclick = (e) => {
      e.stopPropagation();
      shiftDate(-1);
    };
  if (nextBtn)
    nextBtn.onclick = (e) => {
      e.stopPropagation();
      shiftDate(1);
    };

  // History Period Dropdown Logic
  const histDropdown = document.getElementById("history-period-dropdown");
  if (histDropdown) {
    const trigger = histDropdown.querySelector(".dropdown-trigger");
    const items = histDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = histDropdown.classList.contains("open");
      document.querySelectorAll(".custom-dropdown.open").forEach((d) => {
        if (d !== histDropdown) d.classList.remove("open");
      });
      histDropdown.classList.toggle("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        selectedDayFilter = item.dataset.value;
        histDropdown.classList.remove("open");
        updateDateLabel();
        renderStats();
      };
    });
  }

  // Initial syncs
  syncHistoryPresets();
  updateDateLabel();

  // View Navigation Logic

  const attachNav = (id, view) => {
    const el = document.getElementById(id);
    if (el)
      el.onclick = (e) => {
        e.stopPropagation();
        switchView(view);
      };
  };

  attachNav("nav-history", "history");
  attachNav("nav-analytics", "analytics");
  attachNav("nav-settings", "settings");

  const navKeybinds = document.getElementById("nav-keybinds");
  if (navKeybinds) {
    navKeybinds.onclick = (e) => {
      e.stopPropagation();
      switchView("keybinds");
    };
  }

  const resetKeybindsBtn = document.getElementById("reset-keybinds");
  if (resetKeybindsBtn) {
    resetKeybindsBtn.onclick = (e) => {
      e.stopPropagation();
      showConfirmModal({
        title: "Reset Shortcuts?",
        message: "Are you sure you want to restore all keyboard shortcuts to their default settings?",
        confirmText: "Reset",
        cancelText: "Cancel",
        icon: "⌨️",
        onConfirm: () => {
          keybindSettings = {
            toggleSidebar: "Alt+S",
            toggleFloating: "Alt+F",
            toggleDislike: "Alt+D",
            toggleShorts: "Alt+B",
            navHistory: "Alt+Q",
            navAnalytics: "Alt+W",
            navChannels: "Alt+E",
            navBackup: "Alt+R",
            navSettings: "Alt+T",
            navShortcuts: "Alt+Y",
            manualBackup: "Alt+U"
          };
          if (typeof safeStorageSet === "function") {
            safeStorageSet({ ytt_keybind_settings: keybindSettings });
          }
          if (typeof renderKeybinds === "function") renderKeybinds();
        }
      });
    };
  }

  const navBackup = document.getElementById("nav-backup");
  if (navBackup) {
    navBackup.onclick = (e) => {
      e.stopPropagation();
      switchView("backup");
      renderBackups();
    };
  }

  const backToSettings = document.getElementById("back-to-settings");
  if (backToSettings) {
    backToSettings.onclick = (e) => {
      e.stopPropagation();
      switchView("settings");
    };
  }

  const navToChannels = document.getElementById("nav-to-channels");
  if (navToChannels) {
    navToChannels.onclick = (e) => {
      e.stopPropagation();
      switchView("channel-distribution");
    };
  }

  // Remove the old nav-backup-view button listener (no longer in HTML)

  // Settings Controls
  const shortsToggle = document.getElementById("shorts-blocker-toggle");
  if (shortsToggle) {
    shortsToggle.onchange = (e) => {
      e.stopPropagation();
      shortsBlockerSettings.enabled = shortsToggle.checked;
      saveShortsBlockerSettings();
      applyShortsBlockerState();
    };
  }

  const dislikeToggle = document.getElementById("dislike-count-toggle");
  if (dislikeToggle) {
    dislikeToggle.onchange = (e) => {
      e.stopPropagation();
      console.log("YTT: Dislike toggled:", dislikeToggle.checked);
      dislikeCountSettings.enabled = dislikeToggle.checked;
      saveDislikeCountSettings();
      // Apply state immediately, force-fetching if enabled
      applyDislikeCountState();
    };
  }

  const breakToggle = document.getElementById("break-enabled-toggle");
  if (breakToggle) {
    breakToggle.onchange = (e) => {
      e.stopPropagation();
      breakSettings.enabled = breakToggle.checked;
      saveBreakSettings();
      if (!breakSettings.enabled) {
        continuousWatchStart = null;
        breakModalShown = false;
      }
    };
  }

  const workUrlInput = document.getElementById("setting-work-url");
  if (workUrlInput) {
    const updateWorkUrl = () => {
      let url = workUrlInput.value.trim();
      if (url && !url.startsWith("http")) url = "https://" + url;
      breakSettings.workUrl = url || "https://www.google.com";
      saveBreakSettings();
    };
    workUrlInput.onchange = updateWorkUrl;
    workUrlInput.oninput = updateWorkUrl;
  }

  const intervalMinus = document.getElementById("interval-minus");
  const intervalPlus = document.getElementById("interval-plus");
  const intervalValue = document.getElementById("interval-value");

  if (intervalMinus) {
    intervalMinus.onclick = (e) => {
      e.stopPropagation();
      breakSettings.intervalValue = Math.max(1, breakSettings.intervalValue - 1);
      if (intervalValue) intervalValue.value = breakSettings.intervalValue;
      saveBreakSettings();
    };
  }
  if (intervalPlus) {
    intervalPlus.onclick = (e) => {
      e.stopPropagation();
      breakSettings.intervalValue = Math.min(1440, (breakSettings.intervalValue || 15) + 1);
      if (intervalValue) intervalValue.value = breakSettings.intervalValue;
      saveBreakSettings();
    };
  }
  if (intervalValue) {
    const updateInterval = () => {
      let val = parseInt(intervalValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 1440) val = 1440;
      breakSettings.intervalValue = val;
      saveBreakSettings();
    };
    intervalValue.onchange = () => {
      // Force constraints on blur
      let val = parseInt(intervalValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 1440) val = 1440;
      intervalValue.value = val;
      updateInterval();
    };
    intervalValue.oninput = updateInterval;
  }

  const unitDropdown = document.getElementById("interval-unit-dropdown");
  if (unitDropdown) {
    const trigger = unitDropdown.querySelector(".dropdown-trigger");
    const items = unitDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = unitDropdown.classList.contains("open");
      document.querySelectorAll(".custom-dropdown.open").forEach((d) => {
        if (d !== unitDropdown) d.classList.remove("open");
      });
      unitDropdown.classList.toggle("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = item.dataset.value;
        breakSettings.intervalUnit = value;
        saveBreakSettings();

        unitDropdown.dataset.value = value;
        const displayLabel = {
          minutes: "min",
          seconds: "sec",
          hours: "hr",
        }[value];
        trigger.querySelector("span").textContent = displayLabel || value;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");
        unitDropdown.classList.remove("open");
      };
    });
  }

  const sfToggle = document.getElementById("smart-fullscreen-toggle");
  if (sfToggle) {
    sfToggle.onchange = (e) => {
      e.stopPropagation();
      smartFullscreenSettings.enabled = sfToggle.checked;
      saveSmartFullscreenSettings();
    };
  }

  const opacityToggle = document.getElementById("opacity-enabled-toggle");
  const opacitySlider = document.getElementById("opacity-value-slider");
  const opacityLabel = document.getElementById("opacity-percentage-label");
  const opacitySliderContainer = document.getElementById("opacity-slider-container");

  if (opacityToggle) {
    opacityToggle.onchange = (e) => {
      e.stopPropagation();
      opacitySettings.enabled = opacityToggle.checked;
      if (opacitySliderContainer) {
        opacitySliderContainer.style.display = opacityToggle.checked ? "flex" : "none";
      }
      saveOpacitySettings();
      applyOpacityState();
    };
  }

  if (opacitySlider) {
    // Initial color sync
    updateSliderProgress(opacitySlider);

    opacitySlider.oninput = (e) => {
      e.stopPropagation();
      const val = parseFloat(opacitySlider.value);
      opacitySettings.value = val;
      if (opacityLabel) {
        opacityLabel.textContent = Math.round(val * 100) + "%";
      }
      updateSliderProgress(opacitySlider);
      saveOpacitySettings();
      applyOpacityState();
    };

    opacitySlider.onkeydown = (e) => {
      if (e.key === "ArrowLeft" || e.key === "ArrowRight") {
        e.stopPropagation();
        e.preventDefault();
        const step = 0.01;
        const current = parseFloat(opacitySlider.value);
        if (e.key === "ArrowRight") {
          opacitySlider.value = Math.min(1, current + step);
        } else {
          opacitySlider.value = Math.max(0, current - step);
        }
        // Trigger input event to update UI and state
        opacitySlider.dispatchEvent(new Event('input', { bubbles: true }));
      }
    };
  }

  // Backup Settings
  const backupEnabledToggle = document.getElementById("backup-enabled-toggle");
  if (backupEnabledToggle) {
    backupEnabledToggle.onchange = (e) => {
      e.stopPropagation();
      backupSettings.enabled = backupEnabledToggle.checked;
      saveBackupSettings();
    };
  }

  const backupOnCloseToggle = document.getElementById("backup-on-close-toggle");
  if (backupOnCloseToggle) {
    backupOnCloseToggle.onchange = (e) => {
      e.stopPropagation();
      backupSettings.backupOnClose = backupOnCloseToggle.checked;
      saveBackupSettings();
    };
  }

  const backupReminderToggle = document.getElementById("backup-reminder-toggle");
  const reminderIntervalContainer = document.getElementById("reminder-interval-container");
  if (backupReminderToggle) {
    backupReminderToggle.onchange = (e) => {
      e.stopPropagation();
      backupSettings.reminderEnabled = backupReminderToggle.checked;
      if (reminderIntervalContainer) {
        reminderIntervalContainer.style.display = backupReminderToggle.checked ? "flex" : "none";
      }
      saveBackupSettings();
    };
  }

  const backupDropdown = document.getElementById("backup-interval-dropdown");
  if (backupDropdown) {
    const trigger = backupDropdown.querySelector(".dropdown-trigger");
    const menu = backupDropdown.querySelector(".dropdown-menu");
    const items = backupDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = backupDropdown.classList.contains("open");
      // Close any other open dropdowns first (if we had more)
      document
        .querySelectorAll(".custom-dropdown.open")
        .forEach((d) => d.classList.remove("open"));
      if (!isOpen) backupDropdown.classList.add("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = parseInt(item.dataset.value, 10);
        const label = item.textContent;

        // Update state
        backupSettings.intervalHours = value;
        saveBackupSettings();

        // Update UI
        backupDropdown.dataset.value = value;
        trigger.querySelector("span").textContent = label;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");

        // Close
        backupDropdown.classList.remove("open");
      };
    });
  }

  const reminderMinus = document.getElementById("reminder-interval-minus");
  const reminderPlus = document.getElementById("reminder-interval-plus");
  const reminderValue = document.getElementById("reminder-interval-value");

  if (reminderMinus) {
    reminderMinus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.reminderInterval = Math.max(
        1,
        (backupSettings.reminderInterval || 1) - 1,
      );
      if (reminderValue) reminderValue.value = backupSettings.reminderInterval;
      saveBackupSettings();
    };
  }
  if (reminderPlus) {
    reminderPlus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.reminderInterval = Math.min(10080, (backupSettings.reminderInterval || 1) + 1);
      if (reminderValue) reminderValue.value = backupSettings.reminderInterval;
      saveBackupSettings();
    };
  }
  if (reminderValue) {
    const updateReminderInterval = () => {
      let val = parseInt(reminderValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 10080) val = 10080;
      backupSettings.reminderInterval = val;
      saveBackupSettings();
    };
    reminderValue.onchange = () => {
      let val = parseInt(reminderValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 10080) val = 10080;
      reminderValue.value = val;
      updateReminderInterval();
    };
    reminderValue.oninput = updateReminderInterval;
  }

  const reminderUnitDropdown = document.getElementById(
    "reminder-interval-unit-dropdown",
  );
  if (reminderUnitDropdown) {
    const trigger = reminderUnitDropdown.querySelector(".dropdown-trigger");
    const menu = reminderUnitDropdown.querySelector(".dropdown-menu");
    const items = reminderUnitDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = reminderUnitDropdown.classList.contains("open");
      document
        .querySelectorAll(".custom-dropdown.open")
        .forEach((d) => d.classList.remove("open"));
      if (!isOpen) reminderUnitDropdown.classList.add("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = item.dataset.value;

        backupSettings.reminderUnit = value;
        saveBackupSettings();

        reminderUnitDropdown.dataset.value = value;
        trigger.querySelector("span").textContent = item.textContent;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");
        reminderUnitDropdown.classList.remove("open");
      };
    });
  }

  const testBackupBtn = document.getElementById("test-backup-reminder");
  if (testBackupBtn) {
    testBackupBtn.onclick = (e) => {
      e.stopPropagation();
      safeSendMessage({ action: "TEST_BACKUP_REMINDER" });
    };
  }

  const retentionDropdown = document.getElementById(
    "retention-duration-dropdown",
  );
  if (retentionDropdown) {
    const trigger = retentionDropdown.querySelector(".dropdown-trigger");
    const menu = retentionDropdown.querySelector(".dropdown-menu");
    const items = retentionDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = retentionDropdown.classList.contains("open");
      document
        .querySelectorAll(".custom-dropdown.open")
        .forEach((d) => d.classList.remove("open"));
      if (!isOpen) retentionDropdown.classList.add("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = parseInt(item.dataset.value, 10);
        const label = item.textContent;

        // Update state
        retentionSettings.duration = value;
        saveRetentionSettings();

        // Update UI
        retentionDropdown.dataset.value = value;
        trigger.querySelector("span").textContent = label;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");

        // Sync history filters
        if (typeof syncHistoryPresets === "function") {
          syncHistoryPresets();
        }

        // Close
        retentionDropdown.classList.remove("open");
      };
    });
  }

  const maxBackupsMinus = document.getElementById("max-backups-minus");
  const maxBackupsPlus = document.getElementById("max-backups-plus");
  const maxBackupsValue = document.getElementById("max-backups-value");

  if (maxBackupsMinus) {
    maxBackupsMinus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.maxBackups = Math.max(
        1,
        (backupSettings.maxBackups || 10) - 1,
      );
      if (maxBackupsValue) maxBackupsValue.value = backupSettings.maxBackups;
      saveBackupSettings();
    };
  }
  if (maxBackupsPlus) {
    maxBackupsPlus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.maxBackups = Math.min(
        50,
        (backupSettings.maxBackups || 10) + 1,
      );
      if (maxBackupsValue) maxBackupsValue.value = backupSettings.maxBackups;
      saveBackupSettings();
    };
  }
  if (maxBackupsValue) {
    const updateMaxBackups = () => {
      let val = parseInt(maxBackupsValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 50) val = 50;
      backupSettings.maxBackups = val;
      saveBackupSettings();
    };
    maxBackupsValue.onchange = () => {
      // Force constraints on blur
      let val = parseInt(maxBackupsValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 50) val = 50;
      maxBackupsValue.value = val;
      updateMaxBackups();
    };
    maxBackupsValue.oninput = updateMaxBackups;
  }

  // Close dropdowns on outside click
  document.addEventListener("click", (e) => {
    // If we click inside any custom-dropdown trigger, let its own handler manage it
    if (e.target.closest(".dropdown-trigger")) return;

    document
      .querySelectorAll(".custom-dropdown.open")
      .forEach((d) => d.classList.remove("open"));
  });

  const createBackupBtn = document.getElementById("create-manual-backup");
  const deleteBtn = document.getElementById("delete-all-backups");
  if (deleteBtn) {
    deleteBtn.onclick = () => {
      showConfirmModal({
        title: "Clear All Backups?",
        message:
          "This will permanently delete all stored snapshots in the local database. This action cannot be undone.",
        confirmText: "Clear All",
        cancelText: "Cancel",
        icon: "🗑️",
        onConfirm: () => {
          safeSendMessage({ action: "DELETE_ALL_BACKUPS" }, (response) => {
            if (response && response.success) {
              renderBackups();
            } else {
              alert(
                "Failed to clear backups: " +
                  (response ? response.error : "Unknown error"),
              );
            }
          });
        },
      });
    };
  }

  // Import JSON Click
  const importBtn = document.getElementById("import-backup-json");
  const fileInput = document.getElementById("backup-file-input");

  if (importBtn && fileInput) {
    importBtn.onclick = (e) => {
      e.stopPropagation();
      fileInput.click();
    };

    fileInput.onchange = (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const importedData = JSON.parse(event.target.result);

          // Basic validation
          if (!importedData.allHistory && !importedData.shortsBlockerSettings) {
            throw new Error("Invalid backup file format");
          }

          showConfirmModal({
            title: "Import Backup?",
            message:
              "This will overwrite your current history and settings. Are you sure?",
            confirmText: "Import & Restore",
            cancelText: "Cancel",
            icon: "📥",
            onConfirm: () => {
              importBtn.disabled = true;
              importBtn.textContent = "Importing...";

              safeSendMessage(
                { action: "IMPORT_BACKUP", clientData: importedData },
                (response) => {
                  importBtn.disabled = false;
                  importBtn.textContent = "Import JSON";
                  fileInput.value = ""; // Reset input

                  if (response && response.success) {
                    // Refresh everything instantly without reload
                    // Explicitly update local state variables from response to avoid race conditions
                    if (response.settings) {
                      const s = response.settings;
                      if (s.ytt_shorts_settings)
                        shortsBlockerSettings.enabled =
                          s.ytt_shorts_settings.enabled;
                      if (s.ytt_dislike_settings)
                        dislikeCountSettings.enabled =
                          s.ytt_dislike_settings.enabled;
                      if (s.ytt_break_settings) {
                        breakSettings.enabled = s.ytt_break_settings.enabled;
                        breakSettings.intervalValue =
                          s.ytt_break_settings.intervalValue ??
                          s.ytt_break_settings.intervalMinutes ??
                          15;
                        breakSettings.intervalUnit =
                          s.ytt_break_settings.intervalUnit || "minutes";
                        breakSettings.workUrl = s.ytt_break_settings.workUrl;
                      }
                      if (s.ytt_backup_settings)
                        backupSettings = {
                          ...backupSettings,
                          ...s.ytt_backup_settings,
                        };
                      if (s.ytt_retention_settings)
                        retentionSettings = {
                          ...retentionSettings,
                          ...s.ytt_retention_settings,
                        };
                      if (s.ytt_opacity_settings)
                        opacitySettings = {
                          ...opacitySettings,
                          ...s.ytt_opacity_settings,
                        };
                      if (s.ytt_smart_fullscreen_settings)
                        smartFullscreenSettings = {
                          ...smartFullscreenSettings,
                          ...s.ytt_smart_fullscreen_settings,
                        };
                      if (s.ytt_keybind_settings)
                        keybindSettings = {
                          ...keybindSettings,
                          ...s.ytt_keybind_settings,
                        };

                      // Apply live side-effects
                      if (typeof applyShortsBlockerState === "function")
                        applyShortsBlockerState();
                      if (typeof applyDislikeCountState === "function")
                        applyDislikeCountState();
                      if (typeof applyOpacityState === "function")
                        applyOpacityState();
                      if (typeof applyFloatingPlayerState === "function")
                        applyFloatingPlayerState();
                    }

                    // Give storage.onChanged and DOM a moment to settle for total reliability
                    setTimeout(() => {
                      selectedDayFilter = "today"; // Reset filter specifically for imports
                      syncSettingsUI();
                      switchView("history");
                      renderStats();
                      renderBackups();
                    }, 50);

                    // Show success feedback
                    const originalHtml = importBtn.innerHTML;
                    importBtn.textContent = "Imported!";
                    importBtn.style.color = "#2ecc71";
                    setTimeout(() => {
                      importBtn.innerHTML = originalHtml;
                      importBtn.style.color = "";
                    }, 2000);
                  } else {
                    showAlertModal({
                      title: "Import Failed",
                      message: response
                        ? response.error
                        : "Unknown error occurred during import.",
                      icon: "❌",
                    });
                  }
                },
              );
            },
          });
        } catch (err) {
          showAlertModal({
            title: "Invalid File",
            message:
              "The selected file is not a valid YouTube Time Tracker backup. Please check the JSON format.",
            icon: "⚠️",
          });
          fileInput.value = "";
        }
      };
      reader.readAsText(file);
    };
  }

  if (createBackupBtn) {
    createBackupBtn.onclick = (e) => {
      e.stopPropagation();
      window.triggerManualBackup();
    };
  }

  // Clear Data Action
  const clearDataBtn = document.getElementById("clear-all-data");
  if (clearDataBtn) {
    clearDataBtn.onclick = (e) => {
      e.stopPropagation();

      showConfirmModal({
        title: "Clear All Data?",
        message:
          "Are you sure you want to delete all watch history and reset all settings? This action cannot be undone.",
        confirmText: "Clear All",
        cancelText: "Cancel",
        icon: "🗑️",
        onConfirm: () => {
          clearAllData();

          // Update UI elements immediately
          const intervalVal = document.getElementById("interval-value");
          if (intervalVal) intervalVal.value = breakSettings.intervalValue;

          const sToggle = document.getElementById("shorts-blocker-toggle");
          if (sToggle) sToggle.checked = shortsBlockerSettings.enabled;

          const dToggle = document.getElementById("dislike-count-toggle");
          if (dToggle) dToggle.checked = dislikeCountSettings.enabled;

          const bToggle = document.getElementById("break-enabled-toggle");
          if (bToggle) bToggle.checked = breakSettings.enabled;

          const wUrlInput = document.getElementById("setting-work-url");
          if (wUrlInput) wUrlInput.value = breakSettings.workUrl;

          // Show history view to indicate completion
          switchView("history");
          renderStats();

          // Visual feedback on the button
          const originalHtml = clearDataBtn.innerHTML;
          clearDataBtn.textContent = "Data Cleared!";
          clearDataBtn.style.background = "#2ecc71";
          clearDataBtn.style.color = "white";
          clearDataBtn.style.borderColor = "#2ecc71";
          setTimeout(() => {
            clearDataBtn.innerHTML = originalHtml;
            clearDataBtn.style.background = "";
            clearDataBtn.style.color = "";
            clearDataBtn.style.borderColor = "";
          }, 2000);
        },
      });
    };
  }

  // Filter Section Toggle Logic
  const toggleBtn = document.getElementById("toggle-filter-btn");
  const subheader = document.getElementById("stats-header-filters");
  const toggleStrip = document.getElementById("history-filter-toggle");

  if (toggleBtn && subheader) {
    const toggleFilters = (forceState) => {
      const isCollapsed = subheader.classList.contains("collapsed");
      const shouldCollapse =
        forceState !== undefined ? !forceState : !isCollapsed;

      isFilterCollapsed = shouldCollapse; // Set preference to the manually requested state

      subheader.classList.toggle("collapsed", shouldCollapse);
      toggleBtn.classList.toggle("expanded", !shouldCollapse);

      // Update icon based on state
      toggleBtn.innerHTML = shouldCollapse
        ? icons.chevron_down
        : icons.chevron_up;
    };

    toggleBtn.onclick = (e) => {
      e.stopPropagation();
      toggleFilters();
    };

    // "Drag down" feel - simple version: click on strip also toggles
    if (toggleStrip) {
      let startY = 0;
      toggleStrip.onmousedown = (e) => {
        startY = e.clientY;

        const onMouseMove = (moveEvent) => {
          const dy = moveEvent.clientY - startY;
          if (dy > 20) {
            // Dragged down enough
            toggleFilters(true); // Expand
            cleanup();
          } else if (dy < -20) {
            // Dragged up enough
            toggleFilters(false); // Collapse
            cleanup();
          }
        };

        const cleanup = () => {
          document.removeEventListener("mousemove", onMouseMove);
          document.removeEventListener("mouseup", cleanup);
        };

        document.addEventListener("mousemove", onMouseMove);
        document.addEventListener("mouseup", cleanup);
      };

      // Also allow clicking the strip itself to toggle
      toggleStrip.onclick = (e) => {
        if (e.target === toggleStrip) {
          toggleFilters();
        }
      };
    }
  }

  // Toggle sidebar open/close
  btn.onclick = (e) => {
    if (dragStatus.isDragging) return; // Don't toggle if we were dragging
    e.stopPropagation();
    toggleStats();
  };

  const closeBtn = document.getElementById("close-stats");
  if (closeBtn) {
    closeBtn.onclick = (e) => {
      e.stopPropagation();
      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
      if (typeof restoreIsolation === "function") restoreIsolation();
    };
  }

  // Close on escape
  window.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && isStatsOpen) {
      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
      if (typeof restoreIsolation === "function") restoreIsolation();
    }
  });

  // Scroll Listener for Infinite History
  const statsBody = sidebar.querySelector(".stats-body");
  if (statsBody) {
    statsBody.onscroll = () => {
      if (activeView !== "history" && activeView !== "channel-videos") return;

      // Trigger if we are 200px from the bottom
      const threshold = 200;
      const remaining =
        statsBody.scrollHeight - (statsBody.scrollTop + statsBody.clientHeight);

      if (remaining < threshold) {
        if (activeView === "history") {
          appendHistoryBatch();
        } else if (activeView === "channel-videos") {
          appendChannelVideosBatch();
        }
      }
    };
  }

  // Close on click outside
  document.addEventListener("click", (e) => {
    if (popover && !popover.contains(e.target) && e.target !== trigger) {
      popover.style.display = "none";
    }

    if (isStatsOpen && !sidebar.contains(e.target) && !btn.contains(e.target)) {
      // Robustness: Ignore clicks on spontaneous popups so clearing them
      // during sidebar open doesn't accidentally trigger this "close" logic.
      const ignoreIds = [
        "ytt-backup-reminder",
        "break-reminder-modal",
        "stats-confirm-modal",
        "stats-multitab-toast",
        "stats-multitab-modal",
      ];
      for (const id of ignoreIds) {
        if (document.getElementById(id)?.contains(e.target)) return;
      }

      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
      if (typeof restoreIsolation === "function") restoreIsolation();
    }
  });

  // Sidebar hover logic (simplified as global lock is now primary)
  sidebar.onmouseenter = () => {
    // Already handled by global lock if open
  };
  sidebar.onmouseleave = () => {
    if (!isStatsOpen) document.body.style.overflow = "";
  };

  // Initial UI sync
  switchView(activeView);
  updateDateLabel();

  // Stop propagation of shortcut keys to YouTube when typing in our sidebar
  sidebar.addEventListener(
    "keydown",
    (e) => {
      const tag = e.target.tagName.toLowerCase();
      if (tag === "input" || tag === "textarea" || e.target.isContentEditable) {
        e.stopPropagation();
      }
    },
    false,
  );
}

/**
 * Fetches and renders the list of backups present in IndexedDB.
 */
function renderBackups() {
  const list = document.getElementById("backup-history-list");
  if (!list) return;

  safeSendMessage({ action: "GET_BACKUPS" }, (backups) => {
    if (!backups || backups.length === 0) {
      list.innerHTML =
        '<li class="loading-placeholder">No backups found yet.</li>';
      return;
    }

    list.innerHTML = "";
    backups.forEach((b) => {
      const item = document.createElement("li");
      item.className = "backup-item";
      item.innerHTML = `
                <div class="backup-lead">
                    ${icons.backup}
                </div>
                <div class="backup-info">
                    <span class="backup-date">${b.dateString}</span>
                    <span class="backup-meta">Snapshot - YouTube History</span>
                </div>
                <div class="backup-actions">
                    <button class="backup-btn restore-btn" title="Restore this Backup" data-id="${b.id}">
                        ${icons.restore}
                    </button>
                    <button class="backup-btn download-btn" title="Download as JSON" data-id="${b.id}">
                        ${icons.download}
                    </button>
                    <button class="backup-btn delete-btn" title="Delete Backup" data-id="${b.id}">
                        ${icons.close}
                    </button>
                </div>
            `;

      // Restore Action
      item.querySelector(".restore-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        showConfirmModal({
          title: "Restore this Backup?",
          message:
            "This will completely overwrite your current history and settings with data from this snapshot. Are you sure?",
          confirmText: "Restore Now",
          cancelText: "Cancel",
          icon: "🔄",
          onConfirm: () => {
            safeSendMessage(
              { action: "RESTORE_BACKUP", id: id },
              (response) => {
                if (response && response.success) {
                  // Success feedback: sync UI instantly
                  // Explicitly update local state variables from response to avoid race conditions
                  if (response.settings) {
                    const s = response.settings;
                    if (s.ytt_shorts_settings)
                      shortsBlockerSettings.enabled =
                        s.ytt_shorts_settings.enabled;
                    if (s.ytt_dislike_settings)
                      dislikeCountSettings.enabled =
                        s.ytt_dislike_settings.enabled;
                    if (s.ytt_break_settings) {
                      breakSettings.enabled = s.ytt_break_settings.enabled;
                      breakSettings.intervalValue =
                        s.ytt_break_settings.intervalValue ??
                        s.ytt_break_settings.intervalMinutes ??
                        15;
                      breakSettings.intervalUnit =
                        s.ytt_break_settings.intervalUnit || "minutes";
                      breakSettings.workUrl = s.ytt_break_settings.workUrl;
                    }
                    if (s.ytt_backup_settings)
                      backupSettings = {
                        ...backupSettings,
                        ...s.ytt_backup_settings,
                      };
                    if (s.ytt_retention_settings)
                      retentionSettings = {
                        ...retentionSettings,
                        ...s.ytt_retention_settings,
                      };

                    if (s.ytt_opacity_settings)
                      opacitySettings = {
                        ...opacitySettings,
                        ...s.ytt_opacity_settings,
                      };
                    if (s.ytt_smart_fullscreen_settings)
                      smartFullscreenSettings = {
                        ...smartFullscreenSettings,
                        ...s.ytt_smart_fullscreen_settings,
                      };
                    if (s.ytt_keybind_settings)
                      keybindSettings = {
                        ...keybindSettings,
                        ...s.ytt_keybind_settings,
                      };

                    // Apply live side-effects
                    if (typeof applyShortsBlockerState === "function")
                      applyShortsBlockerState();
                    if (typeof applyDislikeCountState === "function")
                      applyDislikeCountState();
                    if (typeof applyOpacityState === "function")
                      applyOpacityState();
                    if (typeof applyFloatingPlayerState === "function")
                      applyFloatingPlayerState();
                  }

                  // Give storage.onChanged and DOM a moment to settle for total reliability
                  setTimeout(() => {
                    selectedDayFilter = "today"; // Reset filter specifically for restores
                    syncSettingsUI();
                    switchView("history");
                    renderStats();
                    renderBackups();
                  }, 50);
                } else {
                  alert(
                    "Failed to restore: " +
                      (response ? response.error : "Unknown error"),
                  );
                }
              },
            );
          },
        });
      };

      // Download Action
      item.querySelector(".download-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        const date = e.currentTarget
          .closest(".backup-item")
          .querySelector(".backup-date").textContent;

        const btn = e.currentTarget;
        const originalIcon = btn.innerHTML;
        btn.innerHTML = icons.loading || "...";
        btn.disabled = true;

        safeSendMessage({ action: "GET_BACKUP_FULL", id: id }, (fullBackup) => {
          btn.innerHTML = originalIcon;
          btn.disabled = false;

          if (fullBackup && fullBackup.data) {
            // Include a version and timestamp for the JSON file
            const exportData = {
              version: "1.0",
              exportedAt: new Date().toISOString(),
              source: id,
              ...fullBackup.data,
            };

            const blob = new Blob([JSON.stringify(exportData, null, 2)], {
              type: "application/json",
            });
            const url = URL.createObjectURL(blob);
            const a = document.createElement("a");
            a.href = url;
            a.download = `ytt-backup_${date.replace(/[,]/g, "").replace(/[/\s:]/g, "-").replace(/-+/g, "-")}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
          } else {
            alert("Failed to fetch full backup data for download.");
          }
        });
      };

      // Delete Action
      item.querySelector(".delete-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        showConfirmModal({
          title: "Delete Backup?",
          message:
            "Are you sure you want to remove this backup? This cannot be undone.",
          confirmText: "Delete",
          cancelText: "Cancel",
          icon: "🗑️",
          onConfirm: () => {
            safeSendMessage({ action: "DELETE_BACKUP", id: id }, () => {
              renderBackups();
            });
          },
        });
      };

      list.appendChild(item);
    });
  });
}

/**
 * Renders the list of keybinds in the keybinds-view
 */
function renderKeybinds() {
  const container = document.getElementById("keybinds-list-container");
  if (!container) return;

  const categories = [
    {
      title: "Navigation",
      actions: [
        { id: "navHistory", label: "Watch History", desc: "Instantly jump to your watch history timeline", icon: icons.history },
        { id: "navAnalytics", label: "Analytics Stats", desc: "View detailed charts and usage statistics", icon: icons.analytics },
        { id: "navChannels", label: "Channels", desc: "View watch time broken down by channel", icon: icons.analytics },
        { id: "navBackup", label: "Backups & Sync", desc: "Manage your data backups and sync settings", icon: icons.backup },
        { id: "navSettings", label: "Settings Menu", desc: "Access all extension preferences", icon: icons.settings },
        { id: "navShortcuts", label: "Hotkeys", desc: "Open this shortcuts settings page", icon: icons.settings }
      ]
    },
    {
      title: "Feature Controls",
      actions: [
        { id: "toggleSidebar", label: "Toggle Sidebar", desc: "Open or close the time tracker sidebar", icon: icons.history },
        { id: "toggleFloating", label: "Floating Mode", desc: "Toggle the resizable PiP video player", icon: icons.pip },
        { id: "toggleDislike", label: "Dislike Counter", desc: "Toggle visibility of the dislike count", icon: icons.dislike },
        { id: "toggleShorts", label: "Shorts Blocker", desc: "Instantly enable/disable the shorts filter", icon: icons.close },
        { id: "toggleOpacity", label: "Toggle Opacity", desc: "Dim/undim the YouTube background", icon: icons.eye },
        { id: "manualBackup", label: "Manual Backup", desc: "Save a snapshot of your current data", icon: icons.backup }
      ]
    }
  ];

  container.innerHTML = categories.map(cat => `
    <div class="keybind-section">
      <div class="section-title">${cat.title}</div>
      <div class="settings-card">
        ${cat.actions.map(action => `
          <div class="settings-item">
            <div class="settings-item-info">
              <div class="label-with-icon">
                <div class="item-icon">${action.icon}</div>
                <span class="settings-item-label">${action.label}</span>
              </div>
              <span class="settings-item-desc">${action.desc}</span>
            </div>
            <div class="keybind-display" id="bind-${action.id}" data-action="${action.id}" title="Click to remap">
              ${keybindSettings[action.id] || "None"}
            </div>
          </div>
        `).join('')}
      </div>
    </div>
  `).join('');

  // Add click listeners for recording
  container.querySelectorAll(".keybind-display").forEach(display => {
    display.onclick = () => startRecordingKeybind(display);
  });
}

/**
 * Handles the key recording process (Quick Copy pattern)
 * Uses keydown to build combo, keyup to finalize when all released.
 */
let isRecording = false;
function startRecordingKeybind(display) {
  if (isRecording) return;
  isRecording = true;

  const actionId = display.dataset.action;
  const originalText = display.innerText;

  // Visual feedback — highlight active, dim others
  display.classList.add("recording");
  display.innerText = "Press keys...";

  const allDisplays = document.querySelectorAll(".keybind-display");
  allDisplays.forEach(d => {
    if (d !== display) d.style.opacity = "0.3";
  });

  let activeKeys = [];          // Ordered array for display
  let pressedKeysSet = new Set(); // Tracks physical keys to avoid keydown repeats

  function getReadableKeyName(e) {
    const code = e.code;
    const key = e.key;

    // Modifier keys with L/R distinction
    const modifiers = {
      ShiftLeft: "Shift", ShiftRight: "Shift",
      ControlLeft: "Ctrl", ControlRight: "Ctrl",
      AltLeft: "Alt", AltRight: "Alt",
      MetaLeft: "Meta", MetaRight: "Meta"
    };
    if (modifiers[code]) return modifiers[code];

    // Regular keys
    if (key === " ") return "Space";
    if (key.length === 1) return key.toUpperCase();
    return key;
  }

  const handleKeyDown = (e) => {
    e.preventDefault();
    e.stopImmediatePropagation();

    if (e.key === "Escape") {
      cancelRecording();
      return;
    }

    const keyName = getReadableKeyName(e);
    if (!pressedKeysSet.has(e.code)) {
      pressedKeysSet.add(e.code);
      // Avoid duplicate named keys (e.g. ShiftLeft and ShiftRight both become "Shift")
      if (!activeKeys.includes(keyName)) {
        activeKeys.push(keyName);
      }
      display.innerText = activeKeys.join("+");
    }
  };

  const handleKeyUp = (e) => {
    e.preventDefault();
    e.stopImmediatePropagation();

    pressedKeysSet.delete(e.code);

    // When all keys are released and we have a combo, finalize
    if (pressedKeysSet.size === 0 && activeKeys.length > 0) {
      finalizeRecording();
    }
  };

  const finalizeRecording = () => {
    const combination = activeKeys.join("+");
    keybindSettings[actionId] = combination;
    display.innerText = combination;

    // Save to storage
    if (typeof safeStorageSet === "function") {
      safeStorageSet({ ytt_keybind_settings: keybindSettings });
    }
    cleanup();
  };

  const cancelRecording = () => {
    display.innerText = originalText;
    cleanup();
  };

  const cleanup = () => {
    isRecording = false;
    display.classList.remove("recording");
    allDisplays.forEach(d => { d.style.opacity = ""; });
    window.removeEventListener("keydown", handleKeyDown, true);
    window.removeEventListener("keyup", handleKeyUp, true);
    window.removeEventListener("blur", cancelRecording);
  };

  window.addEventListener("keydown", handleKeyDown, true);
  window.addEventListener("keyup", handleKeyUp, true);
  window.addEventListener("blur", cancelRecording);
}

/**
 * Closes all active spontaneous popups (Reminders, Multi-tab warnings)
 * to ensure they don't overlap with the sidebar.
 */
function closeAllActivePopups() {
  // 1. Backup Reminder
  const backupReminder = document.getElementById("ytt-backup-reminder");
  if (backupReminder) {
    const xBtn =
      backupReminder.querySelector("#ytt-reminder-x") ||
      backupReminder.querySelector(".close-btn");
    if (xBtn) xBtn.click();
    else backupReminder.remove();
  }

  // 2. Break Reminder
  const breakModal = document.getElementById("break-reminder-modal");
  if (breakModal) {
    const closeBtn = document.getElementById("break-keep-watching");
    if (closeBtn) closeBtn.click();
    else breakModal.remove();
  }

  // 3. Multi-tab Toast
  const multiTabToast = document.getElementById("stats-multitab-toast");
  if (multiTabToast) {
    const dismissBtn = document.getElementById("toast-dismiss");
    if (dismissBtn) dismissBtn.click();
    else multiTabToast.remove();
  }

  // 4. Multi-tab Modal
  const multiTabModal = document.getElementById("stats-multitab-modal");
  if (multiTabModal) {
    const keepBtn = document.getElementById("modal-keep-this");
    if (keepBtn) keepBtn.click();
    else multiTabModal.remove();
  }
}

window.toggleStats = function() {
  const sidebar = document.getElementById("stats-sidebar");
  const btn = document.getElementById("stats-toggle-btn");
  if (!sidebar || !btn) return;

  isStatsOpen = !isStatsOpen;

  sidebar.classList.toggle("open", isStatsOpen);
  btn.classList.toggle("active", isStatsOpen);

  if (isStatsOpen) {
    closeAllActivePopups();
    document.body.classList.add("stats-sidebar-active");
    document.body.style.overflow = "hidden";
    if (typeof renderStats === "function") renderStats();
    if (typeof isolateModal === "function") isolateModal(sidebar);
    // Auto-focus sidebar for keyboard navigation
    setTimeout(() => sidebar.focus(), 300);
  } else {
    document.body.classList.remove("stats-sidebar-active");
    document.body.style.overflow = "";
    if (typeof restoreIsolation === "function") restoreIsolation();
  }
};
window.switchView = function(viewName) {
  if (viewName !== activeView) {
    viewHistory.push(viewName);
    // Keep stack manageable
    if (viewHistory.length > 20) viewHistory.shift();
  }
  _switchViewInternal(viewName);
};

window.triggerManualBackup = function() {
  const createBackupBtn = document.getElementById("create-manual-backup");
  if (createBackupBtn) {
    createBackupBtn.disabled = true;
    const originalHtml = createBackupBtn.innerHTML;
    createBackupBtn.textContent = "Backing up...";

    safeSendMessage({ action: "CREATE_BACKUP_MANUAL" }, () => {
      createBackupBtn.disabled = false;
      createBackupBtn.innerHTML = originalHtml;
      if (activeView === "backup") renderBackups();
    });
  } else {
    // If btn doesn't exist (not in DOM), just send message
    safeSendMessage({ action: "CREATE_BACKUP_MANUAL" }, () => {
       if (activeView === "backup") renderBackups();
    });
  }
};
function updateSliderProgress(slider) {
  if (!slider) return;
  const val = slider.value;
  const min = slider.min || 0;
  const max = slider.max || 1;
  const percent = ((val - min) / (max - min)) * 100;

  slider.style.background = `linear-gradient(to right, var(--stats-primary) 0%, var(--stats-primary) ${percent}%, var(--stats-input-bg) ${percent}%, var(--stats-input-bg) 100%)`;
}


// ─── stats-tracker/sidebar-ui.js ───────────────────────────────── 
// === Stats Sidebar UI: Toggle button, sidebar creation, drag & resize ===
const SCROLLBAR_PADDING = 30;

function injectStatsUI() {
  if (!document.body) return;
  if (document.getElementById("stats-toggle-btn")) return;

  // Tooltip (Global sibling of sidebar)
  if (!document.getElementById("stats-tooltip")) {
    const tooltip = document.createElement("div");
    tooltip.id = "stats-tooltip";
    tooltip.className = "stats-tooltip";
    document.body.appendChild(tooltip);
  }

  // Load position first to avoid "jump" during navigation
  safeStorageGet("ytt_toggle_pos", (data) => {
    if (document.getElementById("stats-toggle-btn")) return;

    // Toggle Button
    const btn = document.createElement("div");
    btn.id = "stats-toggle-btn";
    btn.innerHTML = `
            ${icons.stats_toggle}
            <span id="stats-timer-badge" class="stats-timer-badge" style="display: none;"></span>
        `;
    btn.title = "YouTube Stats Tracker (Drag to Move)";

    const savedPos = data.ytt_toggle_pos || null;

    // Apply saved position BEFORE appending to DOM to prevent flash
    applyPosition(btn, savedPos);
    document.body.appendChild(btn);

    // Events and initialization
    setupSidebarLogic(btn);
  });
}

/**
 * Applies position to the button. Always uses `left` for horizontal
 * placement so the CSS spring transition works correctly.
 */
function applyPosition(btn, savedPos) {
  const padding = 10;
  const btnSize = 54; // matches CSS width/height

  let { top, snapped } = savedPos || {};

  // Default values
  let topNum = parseInt(top, 10);
  if (isNaN(topNum)) topNum = 80;

  // Vertical boundary
  const maxTop = window.innerHeight - btnSize - padding;
  topNum = Math.max(padding, Math.min(maxTop, topNum));

  // Horizontal: always use `left` so CSS transition animates the spring
  let leftNum;
  if (snapped === "right") {
    leftNum = window.innerWidth - btnSize - SCROLLBAR_PADDING;
  } else {
    leftNum = padding;
    snapped = "left";
  }

  btn.style.top = topNum + "px";
  btn.style.left = leftNum + "px";
  btn.style.bottom = "auto";
  btn.style.right = "auto";

  return { top: topNum, snapped };
}

function setupSidebarLogic(btn) {
  const dragStatus = { isDragging: false };
  let currentSnapped = "right"; // default

  // Read initial snapped state from storage
  safeStorageGet("ytt_toggle_pos", (data) => {
    if (data.ytt_toggle_pos && data.ytt_toggle_pos.snapped) {
      currentSnapped = data.ytt_toggle_pos.snapped;
    }
  });

  // On resize/fullscreen: re-read saved position from storage then re-apply
  const handleViewportChange = () => {
    safeStorageGet("ytt_toggle_pos", (data) => {
      const result = applyPosition(btn, data.ytt_toggle_pos || null);
      currentSnapped = result.snapped;
    });
  };

  let resizeTimer;
  window.addEventListener("resize", () => {
    clearTimeout(resizeTimer);
    resizeTimer = setTimeout(handleViewportChange, 150);
  });

  document.addEventListener("fullscreenchange", handleViewportChange);
  document.addEventListener("webkitfullscreenchange", handleViewportChange);

  let startX, startY, btnStartX, btnStartY;

  btn.onmousedown = (e) => {
    dragStatus.isDragging = false;
    startX = e.clientX;
    startY = e.clientY;
    const rect = btn.getBoundingClientRect();
    btnStartX = rect.left;
    btnStartY = rect.top;

    const onMouseMove = (moveEvent) => {
      const dx = moveEvent.clientX - startX;
      const dy = moveEvent.clientY - startY;

      if (Math.abs(dx) > 5 || Math.abs(dy) > 5) {
        dragStatus.isDragging = true;
        btn.classList.add("dragging");

        let newLeft = btnStartX + dx;
        let newTop = btnStartY + dy;

        // Boundary Constraints
        const padding = 10;
        newLeft = Math.max(
          padding,
          Math.min(window.innerWidth - btn.offsetWidth - padding, newLeft),
        );
        newTop = Math.max(
          padding,
          Math.min(window.innerHeight - btn.offsetHeight - padding, newTop),
        );

        btn.style.left = newLeft + "px";
        btn.style.top = newTop + "px";
        btn.style.bottom = "auto";
        btn.style.right = "auto";
      }
    };

    const onMouseUp = () => {
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);

      if (dragStatus.isDragging) {
        btn.classList.remove("dragging");

        // Springy Edge Snapping — uses `left` so the CSS transition animates
        const rect = btn.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const padding = 10;
        let snapped;

        if (centerX < window.innerWidth / 2) {
          btn.style.left = padding + "px";
          snapped = "left";
        } else {
          btn.style.left =
            window.innerWidth - rect.width - SCROLLBAR_PADDING + "px";
          snapped = "right";
        }

        currentSnapped = snapped;

        // Save state
        setTimeout(() => {
          safeStorageSet({
            ytt_toggle_pos: {
              top: btn.style.top,
              snapped: snapped,
            },
          });
          // Reset dragging status AFTER the click event has a chance to fire
          dragStatus.isDragging = false;
        }, 200);
      }
    };

    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
  };

  // Sidebar
  const sidebar = document.createElement("div");
  sidebar.id = "stats-sidebar";
  sidebar.setAttribute("tabindex", "-1"); // Allow focus for keyboard control
  sidebar.style.outline = "none"; // Hide focus ring

  // Load and Apply Persisted Width from storage
  safeStorageGet("ytt_sidebar_width", (data) => {
    if (data.ytt_sidebar_width) {
      sidebar.style.width = data.ytt_sidebar_width + "px";
    }
  });

  // Add Resizer Handle
  const resizer = document.createElement("div");
  resizer.className = "sidebar-resizer";
  sidebar.appendChild(resizer);

  // Resizing Logic
  let isResizing = false;
  resizer.onmousedown = (e) => {
    e.preventDefault(); // Prevent text selection start
    isResizing = true;
    document.body.classList.add("yt-shorts-resizing-active");
    sidebar.classList.add("resizing");
    resizer.classList.add("active");

    const startX = e.clientX;
    const startWidth = parseInt(getComputedStyle(sidebar).width, 10);

    const onMouseMove = (moveEvent) => {
      if (!isResizing) return;
      const currentX = moveEvent.clientX;
      const delta = startX - currentX; // Moving left increases width
      let newWidth = startWidth + delta;

      // Constraints
      newWidth = Math.max(300, Math.min(800, newWidth));
      sidebar.style.width = newWidth + "px";
    };

    const onMouseUp = () => {
      isResizing = false;
      document.body.classList.remove("yt-shorts-resizing-active");
      sidebar.classList.remove("resizing");
      resizer.classList.add("active");
      safeStorageSet({
        ytt_sidebar_width: parseInt(sidebar.style.width, 10),
      });
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);
    };

    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
  };

  // Insert sidebar HTML template
  sidebar.insertAdjacentHTML("beforeend", getSidebarHTML());
  document.body.appendChild(sidebar);

  // Bind all events (filters, navigation, settings, open/close)
  bindSidebarEvents(sidebar, btn, dragStatus);
}


// ─── stats-tracker/fullscreen-auto-hide.js ─────────────────────── 
// === Fullscreen Auto-hide: Hide toggle button during fullscreen inactivity ===

let autoHideTimeout = null;
const AUTO_HIDE_DELAY = 3000; // 3 seconds

function setupFullscreenAutoHide() {
    // Listen for native browser fullscreen changes
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    document.addEventListener('webkitfullscreenchange', handleFullscreenChange);

    // Watch for pseudo-fullscreen class toggles on the root element
    const observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
            if (mutation.attributeName === 'class') {
                handleFullscreenChange();
            }
        });
    });
    observer.observe(document.documentElement, { attributes: true });

    // Listen for mouse movement to reset timer
    document.addEventListener('mousemove', resetAutoHideTimer);
}

/**
 * Checks if the page is in native fullscreen OR our custom pseudo-fullscreen mode
 */
function isAnyFullscreenActive() {
    const isNative = !!(document.fullscreenElement || document.webkitFullscreenElement);
    const isPseudo = document.documentElement.classList.contains('ytt-pseudo-active');
    return isNative || isPseudo;
}

function handleFullscreenChange() {
    const isFullscreen = isAnyFullscreenActive();
    const btn = document.getElementById('stats-toggle-btn');
    
    if (!btn) return;

    if (isFullscreen) {
        startAutoHideTimer();
    } else {
        stopAutoHideTimer();
        btn.style.opacity = '1';
        btn.style.pointerEvents = 'auto';
    }
}

function resetAutoHideTimer() {
    if (!isAnyFullscreenActive()) return;

    const btn = document.getElementById('stats-toggle-btn');
    if (btn) {
        btn.style.opacity = '1';
        btn.style.pointerEvents = 'auto';
    }

    startAutoHideTimer();
}

function startAutoHideTimer() {
    stopAutoHideTimer();
    autoHideTimeout = setTimeout(() => {
        const btn = document.getElementById('stats-toggle-btn');
        if (btn && !btn.classList.contains('active')) { // Only hide if sidebar is NOT open
            btn.style.opacity = '0';
            btn.style.pointerEvents = 'none'; // Prevent accidental clicks or hover while hidden
        }
    }, AUTO_HIDE_DELAY);
}

function stopAutoHideTimer() {
    if (autoHideTimeout) {
        clearTimeout(autoHideTimeout);
        autoHideTimeout = null;
    }
}


// ─── stats-tracker/smart-fullscreen.js ─────────────────────────── 
// === Floating Player: Native Picture-in-Picture Implementation ===

function setupSmartFullscreen() {
  // We keep the function name for compatibility with bootstrap.js

  // Initial check
  applyFloatingPlayerState();
}

function applyFloatingPlayerState() {
  if (!smartFullscreenSettings.enabled) {
    removeFloatingButton();
    return;
  }

  const controls =
    document.querySelector(".ytp-right-controls") ||
    document.querySelector(".ytp-chrome-controls");

  if (!controls || document.getElementById("ytt-floating-btn")) return;

  const btn = document.createElement("button");
  btn.id = "ytt-floating-btn";
  btn.className = "ytp-button";
  btn.innerHTML = icons.pip;
  btn.style.verticalAlign = "top";

  // Custom Tooltip Logic
  btn.onmouseenter = () => showPlayerTooltip(btn, "Floating Mode (YTT)");
  btn.onmouseleave = () => hidePlayerTooltip();

  btn.onclick = (e) => {
    e.preventDefault();
    toggleNativePiP();
  };

  // Insert at the beginning of right controls
  controls.insertBefore(btn, controls.firstChild);
}

function showPlayerTooltip(target, text) {
  let tooltip = document.getElementById("ytt-player-tooltip");
  if (!tooltip) {
    tooltip = document.createElement("div");
    tooltip.id = "ytt-player-tooltip";
    tooltip.className = "ytt-player-tooltip";
    document.body.appendChild(tooltip);
  }

  tooltip.innerText = text;

  // Position: centered above the button, moved significantly higher
  const rect = target.getBoundingClientRect();
  tooltip.style.left = rect.left + rect.width / 2 + "px";
  tooltip.style.top = rect.top - 48 + "px";
  tooltip.classList.add("visible");
}

function hidePlayerTooltip() {
  const tooltip = document.getElementById("ytt-player-tooltip");
  if (tooltip) tooltip.classList.remove("visible");
}

function removeFloatingButton() {
  const btn = document.getElementById("ytt-floating-btn");
  if (btn) btn.remove();

  // If in PiP, exit it
  if (document.pictureInPictureElement) {
    document.exitPictureInPicture().catch(() => {});
  }
}

let isTogglingPiP = false;

async function toggleNativePiP() {
  if (isTogglingPiP) return;
  isTogglingPiP = true;

  try {
    const video = document.querySelector("video");
    if (!video) return;

    if (document.pictureInPictureElement) {
      console.log("YTT: Exiting Picture-in-Picture mode...");
      await document.exitPictureInPicture();
      // Ensure the video is brought back into view ("bring it back up")
      video.scrollIntoView({ behavior: "smooth", block: "center" });
    } else {
      if (document.pictureInPictureEnabled) {
        console.log("YTT: Entering Picture-in-Picture mode...");
        await video.requestPictureInPicture();

        // Ensure we handle when the user closes the PiP window manually
        video.addEventListener(
          "leavepictureinpicture",
          () => {
            console.log("YTT: Left Picture-in-Picture");
          },
          { once: true },
        );
      } else {
        console.warn(
          "YTT: Picture-in-Picture is not supported in this browser.",
        );
      }
    }
  } catch (err) {
    console.error("YTT: Failed to toggle Picture-in-Picture:", err);
  } finally {
    // Release the lock after a short delay to prevent double-triggering from multiple sources (keydown + command)
    setTimeout(() => {
      isTogglingPiP = false;
    }, 500);
  }
}

// Attach to window for shortcut access
window.toggleNativePiP = toggleNativePiP;

function isWindowSystemFullscreen() {
  return false;
} // Stub for compatibility


// ─── stats-tracker/history-render.js ───────────────────────────── 
// === History View Rendering ===

function renderStats() {
    let displayWatchTime = 0;
    let displayVideos = [];
    let displayDuration = 0;
    
    const now = new Date();
    const today = getDayKey(now);
    const yesterday = getDayKey(new Date(now.getTime() - 86400000));
    
    if (selectedDayFilter === 'today') {
        const data = allHistory[today] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: Date.now() };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    } else if (selectedDayFilter === 'yesterday') {
        const data = allHistory[yesterday] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: 0 };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    } else if (selectedDayFilter.endsWith('days')) {
        // Range-based filtering: today, yesterday, 7days, 15days, 30days, etc.
        const daysToInclude = parseInt(selectedDayFilter);
        for (let i = 0; i < daysToInclude; i++) {
            const date = new Date(now.getTime() - i * 86400000);
            const key = getDayKey(date);
            const dayData = allHistory[key];
            if (dayData) {
                displayWatchTime += dayData.watchTime;
                displayVideos = displayVideos.concat(dayData.videos);
                displayDuration += (dayData.activeTime || 0);
            }
        }
    } else if (selectedDayFilter === 'all') {
        Object.values(allHistory).forEach(day => {
            displayWatchTime += day.watchTime;
            displayVideos = displayVideos.concat(day.videos);
            displayDuration += (day.activeTime || 0);
        });
    } else {
        const data = allHistory[selectedDayFilter] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: 0 };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    }

    const getDisplayTitle = () => {
        if (selectedDayFilter === 'today') return 'Watch History (Today)';
        if (selectedDayFilter === 'yesterday') return 'Watch History (Yesterday)';
        if (selectedDayFilter.endsWith('days')) {
            const days = parseInt(selectedDayFilter);
            return `Watch History (Last ${days} Days)`;
        }
        if (selectedDayFilter === 'all') return 'Watch History (All Time)';
        
        const [y, m, d] = selectedDayFilter.split('-').map(Number);
        const date = new Date(y, m - 1, d);
        return `History for ${date.toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' })}`;
    };

    // --- Phase 1: Structural Rebuild (Full render if view/filter changed) ---
    if (activeView === 'history') {
        const titleEl = document.getElementById('history-title');
        if (titleEl) titleEl.textContent = getDisplayTitle();
        const durationEl = document.getElementById('session-duration');
        const watchTimeEl = document.getElementById('total-watch-time');
        const countEl = document.getElementById('videos-count');
        const listEl = document.getElementById('video-history-list');

        // Update basic counts
        if (durationEl) {
            if (selectedDayFilter === 'today') {
                durationEl.parentElement.style.display = 'flex';
                durationEl.textContent = formatTime(displayDuration);
            } else {
                durationEl.parentElement.style.display = 'none';
            }
        }
        if (watchTimeEl) watchTimeEl.textContent = formatTime(displayWatchTime);
        if (countEl) countEl.textContent = displayVideos.length;

        const needsFullRebuild = (activeView !== lastRenderedView || 
                                  selectedDayFilter !== lastRenderedFilter || 
                                  displayVideos.length !== lastVideoCount);

        if (needsFullRebuild && listEl) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            lastVideoCount = displayVideos.length;

            if (displayVideos.length === 0) {
                listEl.innerHTML = '<div style="text-align:center; padding: 40px; color:#666;">No activity recorded for this period.</div>';
                fullSortedVideos = [];
                loadedVideoCount = 0;
            } else {
                fullSortedVideos = displayVideos.slice().sort((a, b) => {
                    const aTime = a.lastStarted || a.lastUpdated || 0;
                    const bTime = b.lastStarted || b.lastUpdated || 0;
                    return bTime - aTime;
                });
                listEl.innerHTML = '';
                loadedVideoCount = 0;
                appendHistoryBatch();
            }
        }
    } else if (activeView === 'channel-distribution') {
        if (activeView !== lastRenderedView || selectedDayFilter !== lastRenderedFilter) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            renderChannelDistribution(getFilteredAnalyticsData());
        }
    } else if (activeView === 'channel-videos') {
        if (activeView !== lastRenderedView || selectedDayFilter !== lastRenderedFilter) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            renderChannelVideosView(selectedChannelForVideos);
        }
    } else {
        if (activeView !== lastRenderedView || selectedDayFilter !== lastRenderedFilter) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            renderAnalyticsView();
        }
    }

    // --- Phase 2: High-Frequency UI Synchronization (Runs every tick) ---
    if (activeView === 'history' || activeView === 'channel-videos') {
        const targetListId = activeView === 'history' ? 'video-history-list' : 'channel-videos-list';
        const targetList = document.getElementById(targetListId);
        
        if (targetList) {
            const targetVideos = activeView === 'history' ? 
                displayVideos : 
                displayVideos.filter(v => v.channelName === selectedChannelForVideos);

            // Determine which video should be at the top
            let topVideoUid = null;
            const localVideo = targetVideos.find(v => v.uid === currentUid);
            if (localVideo && localVideo.isPlaying) {
                topVideoUid = localVideo.uid;
            } else {
                const latestGlobal = [...targetVideos].sort((a, b) => {
                    const aTime = a.lastStarted || a.lastUpdated || 0;
                    const bTime = b.lastStarted || b.lastUpdated || 0;
                    return bTime - aTime;
                })[0];
                if (latestGlobal) topVideoUid = latestGlobal.uid;
            }

            targetVideos.forEach(videoData => {
                const item = targetList.querySelector(`.history-item[data-uid="${videoData.uid}"]`);
                if (item) {
                    const isActive = videoData.uid === currentUid;
                    item.classList.toggle('active-tab-video', isActive);
                    
                    if (videoData.uid === topVideoUid && item.previousElementSibling) {
                        targetList.prepend(item);
                    }

                    const timeEl = item.querySelector('.time-readout');
                    const percentEl = item.querySelector('.video-percent');
                    const progressBar = item.querySelector('.progress-bar-fill');
                    const percent = videoData.totalDuration > 0 ? Math.round((videoData.watchedDuration / videoData.totalDuration) * 100) : 0;
                    
                    const newTimeText = `${formatTime(Math.round(videoData.currentPosition || 0))} / ${formatTime(Math.round(videoData.totalDuration))}`;
                    if (timeEl && timeEl.textContent !== newTimeText) timeEl.textContent = newTimeText;

                    if (percentEl) {
                        const watchedTimeText = formatTime(Math.round(videoData.watchedDuration));
                        const watchedBadgeSpan = percentEl.closest('.watch-stats').querySelector('.watched-badge span');
                        if (watchedBadgeSpan && watchedBadgeSpan.textContent !== watchedTimeText) {
                            watchedBadgeSpan.textContent = watchedTimeText;
                        }

                        const percentText = `${percent}%`;
                        if (percentEl.textContent !== percentText) percentEl.textContent = percentText;
                    }

                    if (progressBar) {
                        const barPercent = videoData.totalDuration > 0 ? Math.min(100, ((videoData.currentPosition || 0) / videoData.totalDuration) * 100) : 0;
                        const newWidth = `${barPercent}%`;
                        if (progressBar.style.width !== newWidth) progressBar.style.width = newWidth;
                    }
                }
            });
        }
    } else if (activeView === 'channel-distribution') {
        const listEl = document.getElementById('full-channel-list');
        if (listEl) {
            const chanMap = {};
            displayVideos.forEach(v => {
                const c = v.channelName || 'Unknown Channel';
                chanMap[c] = (chanMap[c] || 0) + (v.watchedDuration || 0);
            });

            Object.entries(chanMap).forEach(([chanName, duration]) => {
                const card = listEl.querySelector(`.channel-card-detailed[data-channel="${chanName}"]`);
                if (card) {
                    const percent = displayWatchTime > 0 ? Math.round((duration / displayWatchTime) * 100) : 0;
                    
                    const timeSpan = card.querySelector('.channel-stats-row span:first-child');
                    if (timeSpan) {
                        const newTimeText = formatTime(Math.round(duration));
                        if (timeSpan.textContent !== newTimeText) timeSpan.textContent = newTimeText;
                    }

                    const percentEl = card.querySelector('.channel-percent-detailed');
                    if (percentEl) {
                        const newPercentText = `${percent}%`;
                        if (percentEl.textContent !== newPercentText) percentEl.textContent = newPercentText;
                    }

                    const progressBar = card.querySelector('.channel-progress-fill');
                    if (progressBar) {
                        const newWidth = `${percent}%`;
                        if (progressBar.style.width !== newWidth) progressBar.style.width = newWidth;
                    }
                }
            });
        }
    }
}
function createVideoItemElement(v) {
    const li = document.createElement('li');
    const percent = v.totalDuration > 0 ? Math.round((v.watchedDuration / v.totalDuration) * 100) : 0;
    const isActive = v.uid === currentUid;
    
    li.className = `history-item ${isActive ? 'active-tab-video' : ''}`;
    li.dataset.videoId = v.id;
    li.dataset.uid = v.uid;
    li.dataset.time = Math.floor(v.currentPosition || 0);
    
    li.innerHTML = `
        <img class="history-thumb" src="${v.thumbnail}" alt="thumbnail" onerror="this.onerror=null;this.src='https://www.gstatic.com/youtube/src/web/htdocs/img/favicon_144x144.png';">
        <div class="history-info">
            <div class="video-header-row">
                <div style="flex: 1; min-width: 0;">
                    <span class="video-title" title="${v.title}">${v.title}</span>
                    <span class="video-channel">${v.channelName || ''}</span>
                </div>
                <button class="delete-video-btn" title="Remove from History">${icons.delete}</button>
            </div>
            <div class="video-meta">
                <span class="time-readout">${formatTime(Math.round(v.currentPosition || 0))} / ${formatTime(Math.round(v.totalDuration))}</span>
                <div class="watch-stats">
                    <div class="watched-badge">
                        <span>${formatTime(Math.round(v.watchedDuration))}</span>
                    </div>
                    <span class="video-percent">${percent}%</span>
                </div>
            </div>
            <div class="progress-bar-container">
                <div class="progress-bar-fill" style="width: ${v.totalDuration > 0 ? Math.min(100, ((v.currentPosition || 0) / v.totalDuration) * 100) : 0}%"></div>
            </div>
        </div>
    `;

    li.onclick = (e) => {
        e.stopPropagation();
        const vid = li.dataset.videoId;
        const t = li.dataset.time;
        if (vid && vid !== 'undefined') {
            window.location.href = `https://www.youtube.com/watch?v=${vid}&t=${t}s`;
        }
    };

    const delBtn = li.querySelector('.delete-video-btn');
    if (delBtn) {
        delBtn.onclick = (e) => {
            e.stopPropagation();
            const uid = li.dataset.uid;
            const videoTitle = li.querySelector('.video-title').textContent;

            showConfirmModal({
                title: 'Remove from History?',
                message: `Are you sure you want to remove "${videoTitle}" from your watch history?`,
                confirmText: 'Remove',
                cancelText: 'Cancel',
                icon: '🗑️',
                onConfirm: () => {
                    deleteHistoryVideo(uid);
                    lastVideoCount = -1; // Force rebuild
                    renderStats();
                }
            });
        };
    }
    return li;
}

function appendHistoryBatch() {
    const listEl = document.getElementById('video-history-list');
    const loadingEl = document.getElementById('history-loading');
    if (!listEl || isInfiniteScrolling || loadedVideoCount >= fullSortedVideos.length) {
        if (loadingEl) loadingEl.style.display = 'none';
        return;
    }

    if (loadingEl) loadingEl.style.display = 'flex';
    isInfiniteScrolling = true;

    // Small delay to allow the spinner to show up (even though local render is fast)
    setTimeout(() => {
        const batch = fullSortedVideos.slice(loadedVideoCount, loadedVideoCount + historyPageSize);
        const fragment = document.createDocumentFragment();
        
        batch.forEach(v => {
            fragment.appendChild(createVideoItemElement(v));
        });

        listEl.appendChild(fragment);
        loadedVideoCount += batch.length;
        isInfiniteScrolling = false;
        
        // Hide loading indicator if no more videos
        if (loadedVideoCount >= fullSortedVideos.length && loadingEl) {
            loadingEl.style.display = 'none';
        }
    }, 100);
}


// ─── stats-tracker/analytics-render.js ─────────────────────────── 
// === Analytics Rendering: Bar chart, pie chart, heatmaps, insights ===

let selectedHeatmapYear = "Last 365 Days";

function renderAnalyticsView() {
  const data = getFilteredAnalyticsData();

  // Update Overview Stats
  updateAnalyticsOverview(data);

  // Render Components
  renderMainTrendsChart(data);
  renderWatchDistribution(data);
  renderActivityHeatmap();
  renderDetailedInsights(data);
}

/**
 * Aggregates watch data based on the current global selectedDayFilter
 */
function getPeriodKeys(filter, offset = 0) {
  const now = new Date();
  let keys = [];

  if (filter === "today") {
    const d = new Date(now);
    d.setDate(d.getDate() - offset);
    keys = [getDayKey(d)];
  } else if (filter === "yesterday") {
    const d = new Date(now);
    d.setDate(d.getDate() - 1 - offset);
    keys = [getDayKey(d)];
  } else if (filter.endsWith("days")) {
    const daysCount = parseInt(filter);
    const startOffset = (offset + 1) * daysCount - 1;
    const endOffset = offset * daysCount;
    for (let i = startOffset; i >= endOffset; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      keys.push(getDayKey(d));
    }
  } else if (filter === "all") {
    if (offset === 0) {
      keys = Object.keys(allHistory).sort();
    } else {
      keys = [];
    }
  } else {
    // Specific date YYYY-MM-DD
    const dateParts = filter.split("-").map(Number);
    const d = new Date(dateParts[0], dateParts[1] - 1, dateParts[2]);
    d.setDate(d.getDate() - offset);
    keys = [getDayKey(d)];
  }
  return keys;
}

function isFutureDate(filter) {
  if (
    !filter ||
    filter === "today" ||
    filter === "yesterday" ||
    filter.endsWith("days") ||
    filter === "all"
  )
    return false;
  const dateParts = filter.split("-").map(Number);
  if (dateParts.length !== 3) return false;
  const selectedDate = new Date(dateParts[0], dateParts[1] - 1, dateParts[2]);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return selectedDate > today;
}

/**
 * Aggregates summary statistics for a given set of date keys.
 */
function getPeriodSummary(keys) {
  const stats = {
    totalTime: 0,
    activeDays: 0,
    videoCount: 0,
    topChannel: { name: "None", time: 0 },
  };
  const channelMap = {};

  keys.forEach((key) => {
    const d = allHistory[key];
    if (d && d.watchTime > 0) {
      stats.activeDays++;
      stats.totalTime += d.watchTime;
      stats.videoCount += d.videos ? d.videos.length : 0;
      (d.videos || []).forEach((v) => {
        const c = v.channelName || "Unknown";
        channelMap[c] = (channelMap[c] || 0) + (v.watchedDuration || 0);
        if (channelMap[c] > stats.topChannel.time) {
          stats.topChannel = { name: c, time: channelMap[c] };
        }
      });
    }
  });

  return stats;
}

/**
 * Aggregates watch data based on the current global selectedDayFilter
 */
function getFilteredAnalyticsData() {
  const result = {
    days: [], // { key, label, value, color }
    channels: [], // { label, value }
    totalWatchTime: 0,
    videoCounts: 0,
    averageWatchTime: 0,
    maxDay: { key: "", value: 0 },
  };

  const channelsMap = {};
  const keysToInclude = getPeriodKeys(selectedDayFilter, 0);

  keysToInclude.forEach((key, index) => {
    const dayData = allHistory[key] || {
      watchTime: 0,
      activeTime: 0,
      videos: [],
    };
    const val = dayData.watchTime;

    // Always show labels, but format shorter for larger ranges
    const [y, m, d] = key.split("-");
    const months = [
      "Jan",
      "Feb",
      "Mar",
      "Apr",
      "May",
      "Jun",
      "Jul",
      "Aug",
      "Sep",
      "Oct",
      "Nov",
      "Dec",
    ];
    let label = "";

    if (keysToInclude.length <= 14) {
      label = `${d} ${months[parseInt(m) - 1]}`;
    } else {
      label = `${d}/${m}`;
    }

    result.days.push({
      key,
      label,
      value: val,
      color: dayColors[index % dayColors.length],
      activeTime: dayData.activeTime || 0,
      videoCount: dayData.videos ? dayData.videos.length : 0,
      topVideos: [...(dayData.videos || [])]
        .sort((a, b) => (b.watchedDuration || 0) - (a.watchedDuration || 0))
        .slice(0, 3)
        .map((v) => v.title),
    });

    // Aggregate Channels
    (dayData.videos || []).forEach((v) => {
      const chan = v.channelName || "Unknown Channel";
      const duration = v.watchedDuration || 0;

      if (!channelsMap[chan]) {
        channelsMap[chan] = {
          value: 0,
          thumbnail: v.thumbnail,
          videos: new Map(), // Use Map to track duration per unique video
          topVideo: { title: v.title, duration: duration },
        };
      }

      channelsMap[chan].value += duration;

      // Track duration for this specific video ID to find top video
      const vidId = v.id || v.uid;
      const existingVidData = channelsMap[chan].videos.get(vidId) || {
        duration: 0,
        title: v.title,
      };
      existingVidData.duration += duration;
      channelsMap[chan].videos.set(vidId, existingVidData);

      // Update Top Video if this overall duration is higher
      if (existingVidData.duration > channelsMap[chan].topVideo.duration) {
        channelsMap[chan].topVideo = {
          title: existingVidData.title,
          duration: existingVidData.duration,
        };
      }

      // Prioritize Captured Channel Logo > Captured Video Thumbnail > Generated Fallback
      const thumbFallback = `https://i.ytimg.com/vi/${vidId}/default.jpg`;
      const logo = v.channelThumb || v.thumbnail || thumbFallback;

      // Only update if we don't have a logo yet, or if we have a real channelThumb now
      const isRealLogo = v.channelThumb && !v.channelThumb.startsWith("data:");
      if (!channelsMap[chan].thumbnail || isRealLogo) {
        channelsMap[chan].thumbnail = logo;
      }
    });

    result.totalWatchTime += val;
    result.videoCounts += dayData.videos ? dayData.videos.length : 0;

    if (val > result.maxDay.value) {
      result.maxDay = { key, value: val };
    }
  });

  result.averageWatchTime =
    keysToInclude.length > 0 ? result.totalWatchTime / keysToInclude.length : 0;

  // Sort and finalize channels
  result.channels = Object.entries(channelsMap)
    .map(([label, info]) => ({
      label,
      value: info.value,
      videoCount: info.videos.size,
      thumbnail: info.thumbnail,
      topVideo: info.topVideo.title,
      avgTime: info.value / info.videos.size,
    }))
    .sort((a, b) => b.value - a.value);

  return result;
}

function updateAnalyticsOverview(data) {
  const totalEl = document.getElementById("analytics-total-time");
  const avgEl = document.getElementById("analytics-avg-time");
  const periodEl = document.getElementById("trends-period-label");

  if (totalEl) totalEl.textContent = formatTimeShort(data.totalWatchTime);
  if (avgEl) avgEl.textContent = formatTimeShort(data.averageWatchTime);

  if (periodEl) {
    if (selectedDayFilter === "today") periodEl.textContent = "Today";
    else if (selectedDayFilter === "yesterday")
      periodEl.textContent = "Yesterday";
    else if (selectedDayFilter.endsWith("days"))
      periodEl.textContent = `Last ${parseInt(selectedDayFilter)} Days`;
    else if (selectedDayFilter === "all") periodEl.textContent = "All Time";
    else periodEl.textContent = selectedDayFilter;
  }
}

function formatTimeShort(seconds) {
  if (seconds < 60) return `${Math.round(seconds)}s`;
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  return h > 0 ? `${h}h ${m}m` : `${m}m`;
}

function renderMainTrendsChart(data) {
  const chartContainer = document.getElementById("stats-chart");
  if (!chartContainer) return;

  if (data.days.length === 0) {
    const isFuture = isFutureDate(selectedDayFilter);
    chartContainer.innerHTML = `<div class="no-data-msg">${isFuture ? "Future Date - No activity yet" : "No data for this period"}</div>`;
    return;
  }

  const maxValue = Math.max(...data.days.map((d) => d.value), 3600); // at least 1hr scale

  chartContainer.innerHTML = data.days
    .map((d) => {
      const height = Math.max(4, (d.value / maxValue) * 100);
      const isActive = d.key === getDayKey(new Date());

      // Construct Rich Tooltip HTML
      const [y, m, day] = d.key.split("-");
      const dateObj = new Date(y, m - 1, day);
      const dateStr = dateObj.toLocaleDateString("en-US", {
        weekday: "long",
        month: "short",
        day: "numeric",
      });

      let tooltipContent = `
            <div class="tooltip-date">${dateStr}</div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Watch Time</span>
                <span class="tooltip-stat-value">${formatTime(Math.round(d.value))}</span>
            </div>
        `;

      if (d.activeTime > 0) {
        tooltipContent += `
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Active Time</span>
                    <span class="tooltip-stat-value">${formatTime(Math.round(d.activeTime))}</span>
                </div>
            `;
      }

      tooltipContent += `
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Videos</span>
                <span class="tooltip-stat-value">${d.videoCount}</span>
            </div>
        `;

      if (d.topVideos && d.topVideos.length > 0) {
        tooltipContent += `
                <div class="tooltip-videos-header">Top Videos</div>
                ${d.topVideos.map((title) => `<div class="tooltip-video-item">${title}</div>`).join("")}
            `;
      }

      return `
            <div class="chart-bar-wrapper ${isActive ? "active" : ""}" data-tooltip='${tooltipContent.replace(/'/g, "&apos;")}'>
                <div class="chart-bar-outer">
                    <div class="chart-bar-fill" style="height: ${height}%; background: ${d.color}"></div>
                </div>
                ${d.label ? `<span class="chart-label">${d.label}</span>` : ""}
            </div>
        `;
    })
    .join("");

  // Re-bind tooltips
  bindAnalyticsTooltips(chartContainer);

  // Setup scroll arrows
  initCustomScroll(
    "chart-scroll-track",
    "chart-scroll-left",
    "chart-scroll-right",
  );
}

function initCustomScroll(trackId, leftId, rightId) {
  const track = document.getElementById(trackId);
  const leftArrow = document.getElementById(leftId);
  const rightArrow = document.getElementById(rightId);
  if (!track || !leftArrow || !rightArrow) return;

  // Auto-scroll to end on render
  track.scrollLeft = track.scrollWidth;

  let scrollInterval = null;
  let currentSpeed = 3;
  const baseSpeed = 3;
  const turboSpeed = 12;

  const startScroll = (direction) => {
    stopScroll();
    scrollInterval = setInterval(() => {
      track.scrollLeft += direction * currentSpeed;
    }, 16); // ~60fps
  };

  const stopScroll = () => {
    if (scrollInterval) {
      clearInterval(scrollInterval);
      scrollInterval = null;
    }
    currentSpeed = baseSpeed;
  };

  const enhanceSpeed = () => {
    currentSpeed = turboSpeed;
  };

  leftArrow.onmouseenter = () => startScroll(-1);
  leftArrow.onmouseleave = stopScroll;
  leftArrow.onmousedown = (e) => {
    if (e.button === 0) enhanceSpeed();
  };
  leftArrow.onmouseup = () => (currentSpeed = baseSpeed);

  rightArrow.onmouseenter = () => startScroll(1);
  rightArrow.onmouseleave = stopScroll;
  rightArrow.onmousedown = (e) => {
    if (e.button === 0) enhanceSpeed();
  };
  rightArrow.onmouseup = () => (currentSpeed = baseSpeed);

  // Update arrow visibility based on scroll position
  const updateArrowVisibility = () => {
    const atStart = track.scrollLeft <= 2;
    const atEnd = track.scrollLeft + track.clientWidth >= track.scrollWidth - 2;
    leftArrow.style.opacity = atStart ? "0.15" : "";
    rightArrow.style.opacity = atEnd ? "0.15" : "";
    leftArrow.style.pointerEvents = atStart ? "none" : "";
    rightArrow.style.pointerEvents = atEnd ? "none" : "";
  };

  track.onscroll = updateArrowVisibility;
  // Initial check after render settles
  setTimeout(updateArrowVisibility, 50);
}

function renderWatchDistribution(data) {
  const pieChart = document.getElementById("pie-chart");
  const pieLegend = document.getElementById("pie-legend");
  const centerVal = document.getElementById("pie-total-value");
  if (!pieChart || !pieLegend) return;

  if (centerVal) centerVal.textContent = formatTimeShort(data.totalWatchTime);

  if (data.totalWatchTime === 0 || data.channels.length === 0) {
    const isFuture = isFutureDate(selectedDayFilter);
    pieChart.style.background = "var(--stats-chart-bar-bg)";
    pieLegend.innerHTML = `<div class="legend-empty">${isFuture ? "Future date" : "No activity recorded"}</div>`;
    return;
  }

  // Calculate slices for ALL channels (per user request)
  const sorted = [...data.channels];
  let cumulativePercent = 0;
  const slices = sorted.map((c, i) => {
    const start = cumulativePercent;
    const end = start + (c.value / data.totalWatchTime) * 100;
    cumulativePercent = end;
    return {
      ...c,
      start,
      end,
      color: dayColors[i % dayColors.length],
    };
  });

  const updatePieHighlight = (hoverIdx) => {
    const gradient = slices
      .map((s, i) => {
        let color = s.color;
        if (hoverIdx !== -1 && i !== hoverIdx) {
          // Dim other slices using a simple rgba opacity if they were hex
          // Since they are strings, we'll convert them or just use a dimmed overlay logic.
          // For simplicity, we'll use a helper to dim the hex colors.
          color = hexToRgba(color, 0.2);
        }
        return `${color} ${s.start}% ${s.end}%`;
      })
      .join(", ");
    pieChart.style.background = `conic-gradient(${gradient})`;
  };

  // Helper to dim hex colors
  function hexToRgba(hex, alpha) {
    let r, g, b;
    if (hex.length === 4) {
      r = parseInt(hex[1] + hex[1], 16);
      g = parseInt(hex[2] + hex[2], 16);
      b = parseInt(hex[3] + hex[3], 16);
    } else {
      r = parseInt(hex.slice(1, 3), 16);
      g = parseInt(hex.slice(3, 5), 16);
      b = parseInt(hex.slice(5, 7), 16);
    }
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  }

  pieChart.style.background = `conic-gradient(${slices.map((s) => `${s.color} ${s.start}% ${s.end}%`).join(", ")})`;

  // Render Top 5 as pills + View All button
  pieLegend.innerHTML =
    slices
      .slice(0, 5)
      .map(
        (d) => `
        <div class="legend-item" data-channel="${d.label || d.key}">
            <span class="legend-color" style="background: ${d.color}"></span>
            <span class="legend-label">${d.label || d.key}</span>
            <span class="legend-value">${Math.round((d.value / data.totalWatchTime) * 100)}%</span>
        </div>
    `,
      )
      .join("") +
    `
        <button id="view-all-channels" class="view-more-btn">
            View All Channels
        </button>
    `;

  // Setup "View All Channels" view switching
  const viewAllBtn = document.getElementById("view-all-channels");
  if (viewAllBtn) {
    viewAllBtn.onclick = (e) => {
      if (e) e.stopPropagation();
      activeView = "channel-distribution";
      localStorage.setItem("ytt_active_view", activeView);
      switchView(activeView);
      renderChannelDistribution(data);
    };
  }

  // Interaction for legend items
  pieLegend.querySelectorAll(".legend-item").forEach((item, idx) => {
    item.onmouseenter = () => updatePieHighlight(idx);
    item.onmouseleave = () => updatePieHighlight(-1);
  });

  // Interaction
  const tooltip = document.getElementById("stats-tooltip");
  pieChart.onmousemove = (e) => {
    const rect = pieChart.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    let angle =
      Math.atan2(e.clientY - centerY, e.clientX - centerX) * (180 / Math.PI) +
      90;
    if (angle < 0) angle += 360;
    const percent = (angle / 360) * 100;

    const activeSlice = slices.find(
      (s) => percent >= s.start && percent < s.end,
    );
    if (activeSlice) {
      const pct = Math.round((activeSlice.value / data.totalWatchTime) * 100);
      const avgStr = formatTimeShort(
        activeSlice.avgTime || activeSlice.value / activeSlice.videoCount,
      );
      tooltip.innerHTML = `
                <div class="tooltip-date">${activeSlice.label || activeSlice.key}</div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Watch Time</span>
                    <span class="tooltip-stat-value">${formatTime(Math.round(activeSlice.value))}</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Share</span>
                    <span class="tooltip-stat-value">${pct}%</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Videos</span>
                    <span class="tooltip-stat-value">${activeSlice.videoCount}</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Avg / Video</span>
                    <span class="tooltip-stat-value">${avgStr}</span>
                </div>
                ${
                  activeSlice.topVideo
                    ? `
                    <div class="tooltip-videos-header">Most Watched</div>
                    <div class="tooltip-video-item">${activeSlice.topVideo}</div>
                `
                    : ""
                }
            `;
      tooltip.classList.add("visible");
      positionTooltip(e, tooltip);
      // Highlight the hovered slice
      const sliceIdx = slices.indexOf(activeSlice);
      updatePieHighlight(sliceIdx);
    } else {
      tooltip.classList.remove("visible");
      updatePieHighlight(-1);
    }
  };
  pieChart.onmouseleave = () => {
    tooltip.classList.remove("visible");
    updatePieHighlight(-1);
  };
}

function renderChannelDistribution(data) {
  const listEl = document.getElementById("full-channel-list");
  if (!listEl) return;

  if (!data || !data.channels || data.channels.length === 0) {
    listEl.innerHTML =
      '<div class="loading-placeholder">No channel data available</div>';
    return;
  }

  // Sort all channels by value descending
  const sorted = [...data.channels].sort((a, b) => b.value - a.value);

  listEl.innerHTML = sorted
    .map((c, index) => {
      const percent = Math.round((c.value / data.totalWatchTime) * 100);
      const rank = index + 1;
      const avgStr = formatTimeShort(c.avgTime || c.value / c.videoCount);

      // Generate an elegant letter-avatar if no thumbnail exists
      const channelName = c.label || c.key;
      const firstLetter = channelName.charAt(0).toUpperCase();
      const avatarContent = c.thumbnail
        ? `<img src="${c.thumbnail}" class="channel-avatar-detailed" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';">`
        : "";

      return `
            <div class="channel-card-detailed" data-channel="${channelName}">
                <div class="channel-rank-badge ${rank <= 3 ? "top-rank-badge" : ""}">${rank}</div>
                
                <div class="channel-view-avatar">
                    ${avatarContent}
                    <div class="channel-avatar-fallback" style="${c.thumbnail ? "display:none;" : ""}">
                        ${firstLetter}
                    </div>
                </div>

                <div class="channel-info-detailed">
                    <div class="channel-main-row">
                        <span class="channel-name" title="${channelName}">${channelName}</span>
                        <div class="channel-percent-badge">${percent}%</div>
                    </div>

                    <div class="channel-meta-row">
                        <div class="channel-stats-row">
                            <span>${formatTime(Math.round(c.value))}</span>
                            <span class="stats-dot"></span>
                            <span>${c.videoCount} videos</span>
                            <span class="stats-dot"></span>
                            <span>Avg ${avgStr}</span>
                        </div>

                        ${c.topVideo ? `
                            <div class="channel-top-video-row">
                                <span class="top-video-icon">🏆</span>
                                <span class="top-video-title" title="${c.topVideo}">${c.topVideo}</span>
                            </div>
                        ` : ""}
                    </div>
                </div>
            </div>
        `;
    })
    .join("");

  // Add click listeners
  listEl.querySelectorAll(".channel-card-detailed").forEach((card) => {
    card.onclick = (e) => {
      e.stopPropagation();
      selectedChannelForVideos = card.dataset.channel;
      switchView("channel-videos");
      renderChannelVideosView(selectedChannelForVideos);
    };
  });
}

function renderChannelVideosView(channelName) {
  const titleEl = document.getElementById("channel-videos-title");
  const listEl = document.getElementById("channel-videos-list");
  if (titleEl) titleEl.textContent = `Videos from ${channelName}`;
  if (!listEl) return;

  // Use the current active period keys for filtering
  const keysToInclude = getPeriodKeys(selectedDayFilter || "today", 0);
  let channelVideos = [];

  keysToInclude.forEach((key) => {
    const day = allHistory[key];
    if (day && day.videos) {
      day.videos.forEach((v) => {
        if (v.channelName === channelName) {
          channelVideos.push(v);
        }
      });
    }
  });

  if (channelVideos.length === 0) {
    listEl.innerHTML =
      '<div style="text-align:center; padding: 40px; color:#666;">No videos found for this channel in the selected period.</div>';
    return;
  }

  // Sort by last watched time descending
  fullSortedVideos = channelVideos.sort((a, b) => {
    const aTime = a.lastStarted || a.lastUpdated || 0;
    const bTime = b.lastStarted || b.lastUpdated || 0;
    return bTime - aTime;
  });

  listEl.innerHTML = "";
  loadedVideoCount = 0;
  appendChannelVideosBatch();
}

function appendChannelVideosBatch() {
  const listEl = document.getElementById("channel-videos-list");
  const loadingEl = document.getElementById("channel-videos-loading");
  if (
    !listEl ||
    isInfiniteScrolling ||
    loadedVideoCount >= fullSortedVideos.length
  ) {
    if (loadingEl) loadingEl.style.display = "none";
    return;
  }

  if (loadingEl) loadingEl.style.display = "flex";
  isInfiniteScrolling = true;

  setTimeout(() => {
    const batch = fullSortedVideos.slice(
      loadedVideoCount,
      loadedVideoCount + historyPageSize,
    );
    const fragment = document.createDocumentFragment();

    batch.forEach((v) => {
      if (typeof createVideoItemElement === "function") {
        fragment.appendChild(createVideoItemElement(v));
      }
    });

    listEl.appendChild(fragment);
    loadedVideoCount += batch.length;
    isInfiniteScrolling = false;

    if (loadedVideoCount >= fullSortedVideos.length && loadingEl) {
      loadingEl.style.display = "none";
    }
  }, 100);
}

function renderActivityHeatmap() {
  const container = document.getElementById("activity-heatmap");
  const selectorContainer = document.getElementById("heatmap-year-selector");
  if (!container) return;

  // 1. Year Discovery & Selector Rendering
  const years = Array.from(
    new Set(Object.keys(allHistory).map((k) => k.split("-")[0])),
  ).sort((a, b) => b - a);
  const options = ["Last 365 Days", ...years];

  if (selectorContainer) {
    selectorContainer.innerHTML = `
            <div class="custom-dropdown heatmap-year-dropdown" id="heatmap-year-dropdown">
                <div class="dropdown-trigger">
                    <span>${selectedHeatmapYear}</span>
                    <svg class="dropdown-chevron" width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"></polyline></svg>
                </div>
                <div class="dropdown-menu">
                    ${options
                      .map(
                        (y) => `
                        <div class="dropdown-item ${selectedHeatmapYear == y ? "active" : ""}" data-value="${y}">
                            ${y}
                        </div>
                    `,
                      )
                      .join("")}
                </div>
            </div>
        `;

    const dropdown = document.getElementById("heatmap-year-dropdown");
    if (dropdown) {
      const trigger = dropdown.querySelector(".dropdown-trigger");
      trigger.onclick = (e) => {
        e.stopPropagation();
        // Close other open dropdowns first
        document.querySelectorAll(".custom-dropdown.open").forEach((d) => {
          if (d !== dropdown) d.classList.remove("open");
        });
        dropdown.classList.toggle("open");
      };

      dropdown.querySelectorAll(".dropdown-item").forEach((item) => {
        item.onclick = (e) => {
          e.stopPropagation();
          selectedHeatmapYear = item.dataset.value;
          dropdown.classList.remove("open");
          renderActivityHeatmap();
        };
      });
    }
  }

  // 2. Date Range Calculation
  let startDate, endDate, weeks;
  const now = new Date();
  const monthNames = [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
    "Jul",
    "Aug",
    "Sep",
    "Oct",
    "Nov",
    "Dec",
  ];
  const days = ["", "Mon", "", "Wed", "", "Fri", ""];

  if (selectedHeatmapYear === "Last 365 Days") {
    endDate = new Date(now);
    startDate = new Date(now);
    startDate.setDate(now.getDate() - 364);
    // Align start to Sunday
    while (startDate.getDay() !== 0) {
      startDate.setDate(startDate.getDate() - 1);
    }
    // Calculate weeks needed to cover from aligned startDate to today
    const diffTime = Math.abs(endDate - startDate);
    weeks = Math.ceil(
      (diffTime + 1000 * 60 * 60 * 24) / (1000 * 60 * 60 * 24 * 7),
    );
    // Ensure at least 53 weeks for consistent "Year" look
    if (weeks < 53) weeks = 53;
  } else {
    const year = parseInt(selectedHeatmapYear);
    startDate = new Date(year, 0, 1);
    endDate = new Date(year, 11, 31);
    // Align start to the first Sunday on or before Jan 1
    while (startDate.getDay() !== 0) {
      startDate.setDate(startDate.getDate() - 1);
    }
    // Calculate weeks needed to cover the whole year (or until today if current year)
    const targetEnd = year === now.getFullYear() ? new Date(now) : endDate;
    const diffTime = Math.abs(targetEnd - startDate);
    weeks = Math.ceil(
      (diffTime + 1000 * 60 * 60 * 24) / (1000 * 60 * 60 * 24 * 7),
    );

    // However, the grid usually looks better if fully rendered for the selected year
    if (year !== now.getFullYear()) {
      const yearDiff = Math.abs(endDate - startDate);
      weeks = Math.ceil(
        (yearDiff + 1000 * 60 * 60 * 24) / (1000 * 60 * 60 * 24 * 7),
      );
    }
  }

  let heatmapData = [];
  let months = [];
  let lastMonth = -1;

  for (let i = 0; i < weeks * 7; i++) {
    const d = new Date(startDate);
    d.setDate(startDate.getDate() + i);
    const key = getDayKey(d);
    const dayData = allHistory[key] || {
      watchTime: 0,
      activeTime: 0,
      videos: [],
    };
    const val = dayData.watchTime;

    // Month label logic
    if (i % 7 === 0) {
      const m = d.getMonth();
      if (m !== lastMonth) {
        months.push({ name: monthNames[m], index: i / 7 });
        lastMonth = m;
      }
    }

    let level = 0;
    if (val > 0) level = 1;
    if (val > 3600) level = 2;
    if (val > 7200) level = 3;
    if (val > 14400) level = 4;

    const dateStr = d.toLocaleDateString(undefined, {
      weekday: "short",
      month: "short",
      day: "numeric",
      year: "numeric",
    });
    const videos = [...(dayData.videos || [])]
      .sort((a, b) => (b.watchedDuration || 0) - (a.watchedDuration || 0))
      .slice(0, 3);

    let tooltipHtml = `
            <div class="tooltip-date">${dateStr}</div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Watch Time</span>
                <span class="tooltip-stat-value">${formatTime(Math.round(val))}</span>
            </div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Videos</span>
                <span class="tooltip-stat-value">${dayData.videos ? dayData.videos.length : 0}</span>
            </div>
        `;

    if (videos.length > 0) {
      tooltipHtml += `<div class="tooltip-videos-header">Top Videos:</div>`;
      videos.forEach((v) => {
        tooltipHtml += `<div class="tooltip-video-item">${v.title}</div>`;
      });
    }

    heatmapData.push({ key, val, level, tooltipHtml });
  }

  let html = `
        <div class="heatmap-modern-wrapper">
            <div class="heatmap-months-row" style="grid-template-columns: repeat(${weeks}, 11px)">
                ${months
                  .map(
                    (m, i) => `
                    <span class="month-label" style="grid-column: ${m.index + 1}">${m.name}</span>
                `,
                  )
                  .join("")}
            </div>
            <div class="heatmap-main-row">
                <div class="heatmap-days-col">
                    ${days.map((d) => `<span class="day-label">${d}</span>`).join("")}
                </div>
                <div class="heatmap-grid modern" style="grid-template-columns: repeat(${weeks}, 11px)">
                    ${heatmapData
                      .map(
                        (d) => `
                        <div class="heatmap-cell level-${d.level}" data-tooltip="${d.tooltipHtml.replace(/"/g, "&quot;")}"></div>
                    `,
                      )
                      .join("")}
                </div>
            </div>
        </div>
    `;

  container.innerHTML = html;
  bindAnalyticsTooltips(container);

  initCustomScroll(
    "activity-heatmap",
    "heatmap-scroll-left",
    "heatmap-scroll-right",
  );
}

function renderDetailedInsights(currentData) {
  const insightEl = document.getElementById("key-insights");
  if (!insightEl) return;

  const insights = [];
  const filter = selectedDayFilter;
  const isSingleDay =
    filter === "today" ||
    filter === "yesterday" ||
    (filter && filter.includes("-"));

  // 1. Fetch Comparison Data
  const currentKeys = getPeriodKeys(filter, 0);
  const prevKeys = getPeriodKeys(filter, 1);

  const currentStats = getPeriodSummary(currentKeys);
  const prevStats = getPeriodSummary(prevKeys);

  // Handle Empty / Future States
  if (currentStats.totalTime === 0) {
    const isFuture = isFutureDate(filter);
    insightEl.innerHTML = `
            <div class="insight-card-modern empty-state-card">
                <div class="insight-header-row">
                    <span class="insight-icon-vibrant">${isFuture ? "📅" : "🏝️"}</span>
                    <h4>${isFuture ? "Future Date" : "Activity Empty"}</h4>
                </div>
                <p>${isFuture ? "This date is in the future. No data available yet." : "No activity recorded for this day. Go watch some videos!"}</p>
            </div>
        `;
    return;
  }

  // Insight: Trend Analysis
  if (prevStats.totalTime > 0) {
    const diff = currentStats.totalTime - prevStats.totalTime;
    const percent = Math.round((Math.abs(diff) / prevStats.totalTime) * 100);
    const direction = diff >= 0 ? "more" : "less";
    const trendIcon = diff >= 0 ? "📈" : "📉";
    const periodLabel = isSingleDay
      ? filter === "today"
        ? "yesterday"
        : "the day before"
      : "previous period";

    insights.push({
      icon: trendIcon,
      title: "Trend Analysis",
      text: `You watched <strong>${percent}% ${direction}</strong> content compared to ${periodLabel}.`,
    });
  }

  // Insight: Top Activity / Highlights
  if (isSingleDay) {
    if (currentStats.topChannel.time > 0) {
      insights.push({
        icon: "📺",
        title: "Top Channel",
        text: `You spent most of your time on <strong>${currentStats.topChannel.name}</strong>.`,
      });
    }
  } else {
    if (currentData.maxDay.value > 0) {
      insights.push({
        icon: "🔥",
        title: "Peak Activity",
        text: `Your highest watch time was on <strong>${currentData.maxDay.key}</strong> with <strong>${formatTime(Math.round(currentData.maxDay.value))}</strong>.`,
      });
    }

    const avg = currentStats.totalTime / currentData.days.length;
    insights.push({
      icon: "📊",
      title: "Daily Average",
      text: `You are averaging <strong>${formatTimeShort(avg)}</strong> of watch time per day.`,
    });

    const consistency = Math.round(
      (currentStats.activeDays / currentData.days.length) * 100,
    );
    insights.push({
      icon: "🎯",
      title: "Consistency",
      text: `You watched YouTube on <strong>${currentStats.activeDays}</strong> out of the last <strong>${currentData.days.length}</strong> days (${consistency}%).`,
    });
  }

  // Insight: Binge Warning
  const bingeThreshold = 3 * 3600; // 3 hours
  const bingeDays = currentData.days.filter(
    (d) => d.value > bingeThreshold,
  ).length;
  if (bingeDays > 0) {
    insights.push({
      icon: "⚠️",
      title: "Binge Warning",
      text: isSingleDay
        ? `High activity detected! You spent over <strong>3 hours</strong> on YouTube today.`
        : `You had <strong>${bingeDays}</strong> sessions exceeding 3 hours. Consider taking more breaks!`,
    });
  }

  insightEl.innerHTML = insights
    .map(
      (i) => `
        <div class="insight-card-modern">
            <div class="insight-header-row">
                <span class="insight-icon-vibrant">${i.icon}</span>
                <h4>${i.title}</h4>
            </div>
            <p>${i.text}</p>
        </div>
    `,
    )
    .join("");
}

function bindAnalyticsTooltips(container) {
  const tooltip = document.getElementById("stats-tooltip");
  container.querySelectorAll("[data-tooltip]").forEach((el) => {
    el.onmouseenter = (e) => {
      tooltip.innerHTML = el.dataset.tooltip;
      tooltip.classList.add("visible");
      positionTooltip(e, tooltip);
    };
    el.onmousemove = (e) => positionTooltip(e, tooltip);
    el.onmouseleave = () => tooltip.classList.remove("visible");
  });
}

function positionTooltip(e, tooltip) {
  const margin = 15;
  const tooltipWidth = tooltip.offsetWidth;
  const tooltipHeight = tooltip.offsetHeight;
  let left = e.clientX + margin;
  let top = e.clientY - margin;
  if (left + tooltipWidth > window.innerWidth)
    left = e.clientX - tooltipWidth - margin;
  if (top < margin) top = margin;
  if (top + tooltipHeight > window.innerHeight - margin)
    top = window.innerHeight - tooltipHeight - margin;
  tooltip.style.left = left + "px";
  tooltip.style.top = top + "px";
}


// ─── stats-tracker/shortcuts.js ────────────────────────────────── 
// === Shortcuts: Global Keyboard Listener & Executors ===

/**
 * Parses a keybind string like "Alt+S" into an object
 */
function parseKeybind(bindString) {
    const parts = bindString.split('+');
    return {
        key: parts[parts.length - 1].toLowerCase(),
        alt: parts.includes('Alt'),
        shift: parts.includes('Shift'),
        ctrl: parts.includes('Ctrl') || parts.includes('Control'),
        meta: parts.includes('Meta') || parts.includes('Command')
    };
}

/**
 * Checks if a KeyboardEvent matches a keybind string
 */
function matchesKeybind(e, bindString) {
    if (!bindString) return false;
    const bind = parseKeybind(bindString);
    
    // Normalize key name (handle corner cases like 'Escape' vs 'Esc' if needed)
    const pressedKey = e.key.toLowerCase();
    
    // Basic match
    if (pressedKey !== bind.key) return false;
    
    // Modifier match
    if (e.altKey !== bind.alt) return false;
    if (e.shiftKey !== bind.shift) return false;
    if (e.ctrlKey !== bind.ctrl) return false;
    if (e.metaKey !== bind.meta) return false;
    
    return true;
}

window.initShortcuts = function() {
    console.log("YTT: [Shortcuts] Initializing...");
    
    if (typeof keybindSettings === 'undefined') {
        console.error("YTT: [Shortcuts] FATAL - keybindSettings is undefined!");
        return;
    }
    
    console.log("YTT: [Shortcuts] Active Binds:", JSON.stringify(keybindSettings));
    
    window.addEventListener('keydown', (e) => {
        // Skip if currently recording a keybind remap
        if (typeof isRecording !== 'undefined' && isRecording) return;

        // Log all keypresses for debugging if it starts with a modifier
        if (e.altKey || e.ctrlKey || e.shiftKey || e.metaKey) {
            console.log(`YTT: [Keydown] Key: ${e.key}, Alt: ${e.altKey}, Shift: ${e.shiftKey}, Ctrl: ${e.ctrlKey}, Meta: ${e.metaKey}`);
        }

        // 1. Ignore if typing in an input/textarea
        const tag = e.target.tagName.toLowerCase();
        if (tag === 'input' || tag === 'textarea' || e.target.isContentEditable) {
            return;
        }

        // 2. Check each registered shortcut
        // Side navigation
        if (matchesKeybind(e, keybindSettings.toggleSidebar)) {
            console.log("YTT: [Match] toggleSidebar triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof window.toggleStats === 'function') {
                window.toggleStats();
            } else {
                console.error("YTT: [Shortcuts] window.toggleStats is not a function!");
            }
        } 
        else if (matchesKeybind(e, keybindSettings.toggleFloating)) {
            console.log("YTT: [Match] toggleFloating triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof toggleNativePiP === 'function') toggleNativePiP();
        }
        else if (matchesKeybind(e, keybindSettings.toggleDislike)) {
            console.log("YTT: [Match] toggleDislike triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof dislikeCountSettings !== 'undefined') {
                dislikeCountSettings.enabled = !dislikeCountSettings.enabled;
                if (typeof applyDislikeCountState === 'function') applyDislikeCountState();
                saveSettingsInStorage();
            }
        }
        else if (matchesKeybind(e, keybindSettings.toggleShorts)) {
            console.log("YTT: [Match] toggleShorts triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof shortsBlockerSettings !== 'undefined') {
                shortsBlockerSettings.enabled = !shortsBlockerSettings.enabled;
                if (typeof applyShortsBlockerState === 'function') applyShortsBlockerState();
                saveSettingsInStorage();
            }
        }
        else if (matchesKeybind(e, keybindSettings.toggleOpacity)) {
            console.log("YTT: [Match] toggleOpacity triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof opacitySettings !== 'undefined') {
                opacitySettings.enabled = !opacitySettings.enabled;
                if (typeof applyOpacityState === 'function') applyOpacityState();
                if (typeof syncSettingsUI === 'function') syncSettingsUI();
                saveSettingsInStorage();
            }
        }
        // New Navigation and System Shortcuts
        else if (matchesKeybind(e, keybindSettings.navHistory)) {
            handleNavShortcut("history");
        }
        else if (matchesKeybind(e, keybindSettings.navAnalytics)) {
            handleNavShortcut("analytics");
        }
        else if (matchesKeybind(e, keybindSettings.navBackup)) {
            handleNavShortcut("backup");
        }
        else if (matchesKeybind(e, keybindSettings.navSettings)) {
            handleNavShortcut("settings");
        }
        else if (matchesKeybind(e, keybindSettings.navChannels)) {
            handleNavShortcut("channel-distribution");
        }
        else if (matchesKeybind(e, keybindSettings.navShortcuts)) {
            handleNavShortcut("keybinds");
        }
        else if (matchesKeybind(e, keybindSettings.manualBackup)) {
            console.log("YTT: [Match] manualBackup triggered");
            e.preventDefault();
            e.stopImmediatePropagation();
            if (typeof window.triggerManualBackup === "function") {
                window.triggerManualBackup();
            }
        }

        function handleNavShortcut(viewName) {
            console.log(`YTT: [Match] navShortcut -> ${viewName}`);
            e.preventDefault();
            e.stopImmediatePropagation();
            
            // Open sidebar if closed
            if (!isStatsOpen && typeof window.toggleStats === 'function') {
                window.toggleStats();
            }
            
            // Switch view
            if (typeof window.switchView === 'function') {
                window.switchView(viewName);
            }
        }
    }, true); 
    
    console.log("YTT: [Shortcuts] Global listener attached.");

    // Listen for background commands (e.g. for when the tab is minimized)
    chrome.runtime.onMessage.addListener((request) => {
        if (request.action === "TOGGLE_PIP") {
            console.log("YTT: [Command] TOGGLE_PIP received from background");
            if (typeof toggleNativePiP === 'function') toggleNativePiP();
        }
    });
}

function saveSettingsInStorage() {
    // Helper to persist quick toggles triggered via shortcuts
    if (typeof safeStorageSet === 'function') {
        safeStorageSet({
            ytt_shorts_settings: shortsBlockerSettings,
            ytt_dislike_settings: dislikeCountSettings,
            ytt_smart_fullscreen_settings: smartFullscreenSettings,
            ytt_keybind_settings: keybindSettings,
            ytt_opacity_settings: opacitySettings
        });
        try {
            localStorage.setItem("ytt_opacity_fast_path", JSON.stringify(opacitySettings));
        } catch (e) {}
    }
}


// ─── break-reminder/reminder.js ────────────────────────────────── 
// === Break Reminder: Quote fetching, modal, and timer ===

async function fetchZenQuote() {
  return new Promise((resolve) => {
    safeSendMessage({ action: "FETCH_QUOTE" }, (response) => {
      if (response && response.text) {
        resolve(response);
      } else {
        // Randomized local fallbacks if message fails
        const fallbacks = [
          {
            text: "The secret of getting ahead is getting started.",
            author: "Mark Twain",
          },
          {
            text: "It does not matter how slowly you go as long as you do not stop.",
            author: "Confucius",
          },
          {
            text: "Everything you've ever wanted is on the other side of fear.",
            author: "George Addair",
          },
        ];
        resolve(fallbacks[Math.floor(Math.random() * fallbacks.length)]);
      }
    });
  });
}

function showBreakModal(quote) {
  if (document.getElementById("break-reminder-modal")) return;

  // Default fallback if quote failed
  const finalQuote = quote || {
    text: "The secret of getting ahead is getting started.",
    author: "Mark Twain",
  };

  const overlay = document.createElement("div");
  overlay.id = "break-reminder-modal";
  overlay.className = "break-modal-overlay";
  // Accessibility: Role and Aria
  overlay.setAttribute("role", "dialog");
  overlay.setAttribute("aria-modal", "true");
  overlay.setAttribute("aria-labelledby", "break-modal-title");

  overlay.innerHTML = `
        <div class="break-modal">
            <div class="modal-drag-handle"></div>
            <div class="break-modal-icon">☕</div>
            <h2 id="break-modal-title" class="break-modal-title">Time for a Break!</h2>
            <p class="break-modal-subtitle">You've been watching for ${
              breakSettings.intervalValue
            } ${
              breakSettings.intervalUnit === "seconds" ? "seconds" : "minutes"
            } straight.</p>
            <blockquote class="break-modal-quote">
                <p>"${finalQuote.text}"</p>
                <cite>— ${finalQuote.author}</cite>
            </blockquote>
            <div class="break-modal-actions">
                <button id="break-keep-watching" class="break-btn secondary">Keep Watching</button>
                <button id="break-go-work" class="break-btn primary">Go to Work</button>
            </div>
        </div>
    `;
  document.body.appendChild(overlay);

  // Prevent background scroll and selection
  document.body.style.overflow = "hidden";
  document.body.style.userSelect = "none";

  const modal = overlay.querySelector(".break-modal");
  const keepWatchingBtn = document.getElementById("break-keep-watching");
  const goWorkBtn = document.getElementById("break-go-work");

  // Focus the first action button
  setTimeout(() => keepWatchingBtn.focus(), 100);

  // Animate in
  requestAnimationFrame(() => {
    overlay.classList.add("visible");
    if (typeof isolateModal === "function") isolateModal(overlay);
  });

  // Swipe to Dismiss (Mobile)
  let touchStartY = 0;
  let currentY = 0;
  let isSwiping = false;

  modal.addEventListener(
    "touchstart",
    (e) => {
      if (window.innerWidth > 600) return;
      touchStartY = e.touches[0].clientY;
      modal.style.transition = "none";
      isSwiping = true;
    },
    { passive: true },
  );

  modal.addEventListener(
    "touchmove",
    (e) => {
      if (!isSwiping) return;
      currentY = e.touches[0].clientY;
      const deltaY = currentY - touchStartY;

      if (deltaY > 0) {
        // Only allow swiping down
        modal.style.transform = `translateY(${deltaY}px)`;
      }
    },
    { passive: true },
  );

  modal.addEventListener("touchend", () => {
    if (!isSwiping) return;
    isSwiping = false;
    modal.style.transition = "transform 0.3s cubic-bezier(0.16, 1, 0.3, 1)";

    const deltaY = currentY - touchStartY;
    if (deltaY > 120) {
      // Dismiss
      dismissModal();
    } else {
      // Snap back
      modal.style.transform = "translateY(0)";
    }
  });

  const dismissModal = () => {
    overlay.classList.remove("visible");
    document.body.style.overflow = ""; // Restore scroll
    document.body.style.userSelect = ""; // Restore selection

    if (window.innerWidth <= 600) {
      modal.style.transform = "translateY(100%)";
    }
    if (typeof restoreIsolation === "function") restoreIsolation();
    setTimeout(() => overlay.remove(), 400);
    continuousWatchStart = Date.now(); // Reset timer
    breakModalShown = false;
    preFetchedQuote = null; // Clear pre-fetched for next cycle

    // Resume video playback
    const video = document.querySelector("video");
    if (video) video.play();
  };

  // Accessibility: Click outside to close
  overlay.onclick = (e) => {
    if (e.target === overlay) {
      dismissModal();
    }
  };

  // Accessibility: Focus Trap (Tab behavior)
  overlay.onkeydown = (e) => {
    if (e.key === "Tab") {
      const focusables = [keepWatchingBtn, goWorkBtn];
      const first = focusables[0];
      const last = focusables[focusables.length - 1];

      if (e.shiftKey) {
        // Shift + Tab
        if (document.activeElement === first) {
          last.focus();
          e.preventDefault();
        }
      } else {
        // Tab
        if (document.activeElement === last) {
          first.focus();
          e.preventDefault();
        }
      }
    }
    if (e.key === "Escape") {
      dismissModal();
    }
  };

  if (keepWatchingBtn) {
    keepWatchingBtn.onclick = (e) => {
      e.stopPropagation();
      dismissModal();
    };
  }

  if (goWorkBtn) {
    goWorkBtn.onclick = () => {
      window.location.href = breakSettings.workUrl || "https://www.google.com";
    };
  }
}

function updateTimerBadge(remainingMinutes) {
  const badge = document.getElementById("stats-timer-badge");
  if (!badge) return;

  if (!breakSettings.enabled || remainingMinutes <= 0 || breakModalShown) {
    badge.style.display = "none";
    return;
  }

  badge.style.display = "block";
  badge.style.background = "#0f0f0f";

  if (remainingMinutes >= 52560000) { // 100 years
    badge.textContent = `${Math.round(remainingMinutes / 52560000)}cen`;
  } else if (remainingMinutes >= 5256000) { // 10 years
    badge.textContent = `${Math.round(remainingMinutes / 5256000)}dec`;
  } else if (remainingMinutes >= 525600) { // 1 year
    badge.textContent = `${Math.round(remainingMinutes / 525600)}y`;
  } else if (remainingMinutes >= 43200) { // 30 days
    badge.textContent = `${Math.round(remainingMinutes / 43200)}mo`;
  } else if (remainingMinutes >= 10080) { // 7 days
    badge.textContent = `${Math.round(remainingMinutes / 10080)}w`;
  } else if (remainingMinutes >= 1440) { // 1 day
    badge.textContent = `${Math.round(remainingMinutes / 1440)}d`;
  } else if (remainingMinutes >= 60) { // 1 hour
    badge.textContent = `${Math.round(remainingMinutes / 60)}h`;
  } else if (remainingMinutes >= 1) { // 1 minute
    badge.textContent = `${Math.round(remainingMinutes)}m`;
  } else { // Seconds
    badge.textContent = `${Math.round(remainingMinutes * 60)}s`;
    badge.style.background = "#FF0033"; // High urgency
  }
}

function checkBreakReminder() {
  if (!breakSettings.enabled) {
    updateTimerBadge(0);
    return;
  }

  const video = document.querySelector("video");
  if (!video || video.paused) {
    continuousWatchStart = null;
    breakModalShown = false;
    updateTimerBadge(0);
    return;
  }

  if (!continuousWatchStart) {
    continuousWatchStart = Date.now();
    return;
  }

  const elapsed = (Date.now() - continuousWatchStart) / 1000 / 60; // minutes
  let intervalMinutes;
  if (breakSettings.intervalUnit === "hours") {
    intervalMinutes = breakSettings.intervalValue * 60;
  } else if (breakSettings.intervalUnit === "seconds") {
    intervalMinutes = breakSettings.intervalValue / 60;
  } else {
    intervalMinutes = breakSettings.intervalValue;
  }
  
  // Pre-fetch quote 5 seconds before the interval (5/60 minutes)
  const preFetchThreshold = intervalMinutes - 5 / 60;
  if (elapsed >= preFetchThreshold && !preFetchedQuote && !isFetchingQuote) {
    isFetchingQuote = true;
    fetchZenQuote().then((quote) => {
      preFetchedQuote = quote;
      isFetchingQuote = false;
    });
  }

  if (elapsed >= intervalMinutes && !breakModalShown) {
    // Don't show if sidebar is open
    const sidebar = document.getElementById("stats-sidebar");
    if (sidebar && sidebar.classList.contains("open")) return;

    breakModalShown = true;
    video.pause();
    showBreakModal(preFetchedQuote);
    updateTimerBadge(0);
  } else {
    updateTimerBadge(intervalMinutes - elapsed);
  }
}
// }


// ─── dislike-counter/dislike-counter.js ────────────────────────── 
// === Dislike Counter: Attribute Observation Version (Take 12) ===

const dislikeDataCache = {};
let pendingDislikeFetch = null;
let globalObserver = null;
let isDislikeInitialized = false;

// Registry to prevent duplicate observers on buttons
const buttonObservers = new WeakMap();

function getVideoId() {
  const watchFlexy = document.querySelector("ytd-watch-flexy");
  if (watchFlexy && watchFlexy.getAttribute("video-id")) {
    return watchFlexy.getAttribute("video-id");
  }
  const urlParams = new URLSearchParams(window.location.search);
  const v = urlParams.get("v");
  if (v) return v;
  const pathParts = window.location.pathname.split("/");
  if (pathParts[1] === "shorts") return pathParts[2];
  return null;
}

function isElementVisible(el) {
    if (!el) return false;
    const style = window.getComputedStyle(el);
    if (style.display === "none" || style.visibility === "hidden" || style.opacity === "0") return false;
    return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
}

/**
 * Recursive helper to find ALL elements inside Shadow DOM.
 */
function findAllDeep(selector, root = document, results = []) {
    const nodes = root.querySelectorAll(selector);
    nodes.forEach(n => results.push(n));

    const walkers = document.createTreeWalker(root, NodeFilter.SHOW_ELEMENT);
    let node = walkers.nextNode();
    while (node) {
        if (node.shadowRoot) {
            findAllDeep(selector, node.shadowRoot, results);
        }
        node = walkers.nextNode();
    }
    return results;
}

function isButtonInComment(btn) {
    let curr = btn;
    while (curr && curr !== document.body) {
        const name = curr.nodeName || "";
        if (name.includes("COMMENT")) return true;
        
        if (curr.parentNode instanceof ShadowRoot) {
            curr = curr.parentNode.host;
        } else {
            curr = curr.parentElement;
        }
    }
    return false;
}

function findDislikeButton() {
    const selectors = [
        "yt-animated-action-button-view-model:nth-child(2) button",
        "dislike-button-view-model button",
        "#segmented-dislike-button button",
        "ytd-dislike-button-renderer button"
    ];

    for (const sel of selectors) {
        const matches = findAllDeep(sel);
        const visibleBtn = matches.find(btn => {
            if (!isElementVisible(btn)) return false;
            if (isButtonInComment(btn)) return false;

            const ariaLabel = (btn.getAttribute("aria-label") || "").toLowerCase();
            const title = (btn.getAttribute("title") || "").toLowerCase();
            return ariaLabel.includes("dislike") || title.includes("dislike");
        });
        if (visibleBtn) return visibleBtn;
    }
    return null;
}

function findLikeButton() {
    const selectors = [
        "yt-animated-action-button-view-model:nth-child(1) button",
        "like-button-view-model button",
        "#segmented-like-button button",
        "ytd-like-button-renderer button"
    ];

    for (const sel of selectors) {
        const matches = findAllDeep(sel);
        const visibleBtn = matches.find(btn => {
            if (!isElementVisible(btn)) return false;
            if (isButtonInComment(btn)) return false;

            const ariaLabel = (btn.getAttribute("aria-label") || "").toLowerCase();
            const title = (btn.getAttribute("title") || "").toLowerCase();
            return (ariaLabel.includes("like") || title.includes("like")) && !ariaLabel.includes("dislike");
        });
        if (visibleBtn) return visibleBtn;
    }
    return null;
}

function findTextSlot(button) {
    if (!button) return null;
    const root = button.shadowRoot || button;
    return root.querySelector(".yt-core-attributed-string, .yt-spec-button-shape-next__button-text-content");
}

function formatDislikeCount(count) {
  if (count >= 1000000) {
    const val = count / 1000000;
    return (val % 1 === 0 ? val.toFixed(0) : val.toFixed(1)) + "M";
  }
  if (count >= 1000) {
    const val = count / 1000;
    return (val % 1 === 0 ? val.toFixed(0) : val.toFixed(1)) + "K";
  }
  return count.toString();
}

async function fetchDislikeCount(videoId) {
  return new Promise((resolve) => {
    safeSendMessage({ action: "GET_DISLIKE_COUNT", videoId }, (data) => {
      resolve(data);
    });
  });
}

/**
 * Initialize global listeners once.
 */
function initDislikeCounter() {
    if (isDislikeInitialized) return;
    isDislikeInitialized = true;

    // YouTube SPA navigation hook
    window.addEventListener("yt-navigate-finish", () => {
        console.log("YTT: [Dislike] SPA Navigation detected.");
        setTimeout(tryRenderDislike, 500); 
    });

    console.log("YTT: [Dislike] System initialized.");
}

function isDislikedState(btn) {
    if (!btn) return false;
    const ariaPressed = btn.getAttribute("aria-pressed") === "true";
    const ariaLabel = (btn.getAttribute("aria-label") || "").toLowerCase();
    
    // Check for various ways YouTube signals an active state
    const isLabelActive = ariaLabel.includes("remove") || ariaLabel.includes("disliked");
    const hasActiveClass = btn.classList.contains("yt-spec-button-shape-next--active");
    return ariaPressed || hasActiveClass || isLabelActive;
}

function observeButtonStates(videoId, dislikeBtn, likeBtn) {
    if (!dislikeBtn || !likeBtn) return;
    
    // Cleanup old observers/listeners
    const cleanup = (btn) => {
        const obs = buttonObservers.get(btn);
        if (obs) {
            if (obs.disconnect) obs.disconnect();
            if (obs.clickHandler && btn.removeEventListener) {
                btn.removeEventListener("click", obs.clickHandler);
            }
            buttonObservers.delete(btn);
        }
    };

    cleanup(dislikeBtn);
    cleanup(likeBtn);

    const updateCount = () => {
        const data = dislikeDataCache[videoId];
        if (!data) return;

        const currentState = isDislikedState(dislikeBtn);
        const lastKnownState = dislikeBtn.dataset.yttWasDisliked === "true";

        if (currentState !== lastKnownState) {
            if (currentState) {
                data.dislikes++;
                console.log("YTT: [Dislike] State change: Disliked (+1)");
            } else {
                data.dislikes--;
                console.log("YTT: [Dislike] State change: Un-disliked (-1)");
            }
            dislikeBtn.dataset.yttWasDisliked = currentState;
            doRender(data, videoId, dislikeBtn);
        }
    };

    // 1. Mutation Observer for attribute changes
    const observer = new MutationObserver(updateCount);
    const config = { attributes: true, attributeFilter: ["aria-pressed", "aria-label", "class"] };
    observer.observe(dislikeBtn, config);
    observer.observe(likeBtn, config);

    // 2. Click listeners for immediate response (sometimes attributes lag)
    const handleClick = () => {
        // Small delay to let YouTube's internal state update
        setTimeout(updateCount, 50);
        setTimeout(updateCount, 250); // Second check for slow UI updates
    };

    dislikeBtn.addEventListener("click", handleClick);
    likeBtn.addEventListener("click", handleClick);

    // Store for future cleanup
    const record = { disconnect: () => observer.disconnect(), clickHandler: handleClick };
    buttonObservers.set(dislikeBtn, record);
    buttonObservers.set(likeBtn, record);
}

function tryRenderDislike() {
  if (!dislikeCountSettings || !dislikeCountSettings.enabled) return;
  
  initDislikeCounter();

  const videoId = getVideoId();
  if (!videoId) return;

  const dislikeBtn = findDislikeButton();
  const likeBtn = findLikeButton();
  if (!dislikeBtn) return;

  const hasLabel = (dislikeBtn.shadowRoot || dislikeBtn).querySelector(".ytt-hijacked-label");
  if (dislikeBtn.dataset.yttDislikeVideo === videoId && hasLabel) {
      // Still on same video and label exists - keep it as is.
      return;
  }

  if (dislikeDataCache[videoId]) {
     const data = dislikeDataCache[videoId];
     dislikeBtn.dataset.yttWasDisliked = isDislikedState(dislikeBtn);
     doRender(data, videoId, dislikeBtn);
     observeButtonStates(videoId, dislikeBtn, likeBtn);
  } else if (pendingDislikeFetch !== videoId) {
     pendingDislikeFetch = videoId;
     fetchDislikeCount(videoId).then(data => {
         pendingDislikeFetch = null;
         if (data) {
             dislikeDataCache[videoId] = data;
             const currentDislikeBtn = findDislikeButton();
             const currentLikeBtn = findLikeButton();
             if (currentDislikeBtn) {
                 currentDislikeBtn.dataset.yttWasDisliked = isDislikedState(currentDislikeBtn);
                 doRender(data, videoId, currentDislikeBtn);
                 observeButtonStates(videoId, currentDislikeBtn, currentLikeBtn);
             }
         }
     });
  }
}

function forceVisibility(btn) {
    // Only force the button element itself and its shadow host ancestors.
    // Do NOT touch the internal content container (icon parent) — that has
    // flex layout we manage separately and overwriting it breaks spacing.
    let curr = btn;
    for (let i = 0; i < 4; i++) {
        if (!curr || curr === document.body) break;
        if (curr.nodeType === 1) {
            curr.style.setProperty("overflow", "visible", "important");
            // Only set width/display on the outer wrapper (not inside shadow root)
            if (!(curr.parentNode instanceof ShadowRoot)) {
                curr.style.setProperty("width", "auto", "important");
                curr.style.setProperty("min-width", "unset", "important");
            }
        }
        
        if (curr.parentNode instanceof ShadowRoot) {
            curr = curr.parentNode.host;
        } else {
            curr = curr.parentElement;
        }
    }
}

function doRender(data, videoId, btn) {
    if (!btn || isButtonInComment(btn)) return;

    // Final sanity check that this is actually a dislike button
    const ariaLabel = (btn.getAttribute("aria-label") || "").toLowerCase();
    const title = (btn.getAttribute("title") || "").toLowerCase();
    if (!ariaLabel.includes("dislike") && !title.includes("dislike")) return;

    const countText = formatDislikeCount(data.dislikes);
    const root = btn.shadowRoot || btn;
    let label = root.querySelector(".ytt-hijacked-label");

    if (!label) {
        label = document.createElement("span");
        label.className = "ytt-hijacked-label";
    }

    const icon = root.querySelector("yt-icon, svg, .yt-spec-button-shape-next__icon");
    const isShorts = window.location.pathname.includes("/shorts");

    if (icon) {
        // Always re-position: insert right after the icon
        if (label.previousElementSibling !== icon) {
            icon.insertAdjacentElement("afterend", label);
        }

        // Style the icon's parent as a flex container — run on EVERY render
        const parent = icon.parentElement;
        if (parent && parent.nodeType === 1) {
            parent.style.setProperty("display", "flex", "important");
            parent.style.setProperty("flex-direction", isShorts ? "column" : "row", "important");
            parent.style.setProperty("align-items", "center", "important");
            parent.style.setProperty("justify-content", "flex-start", "important");
            parent.style.setProperty("flex-wrap", "nowrap", "important");
            parent.style.setProperty("overflow", "visible", "important");
            parent.style.removeProperty("gap"); // Let margins handle spacing exclusively
        }

        // Keep icon stable
        icon.style.setProperty("flex-shrink", "0", "important");
        icon.style.setProperty("display", "inline-flex", "important");
        icon.style.setProperty("margin", "0", "important");
    } else if (!label.parentElement) {
        root.appendChild(label);
    }

    label.textContent = countText;
    label.classList.add("ytt-hijacked-label");
    btn.dataset.yttDislikeVideo = videoId;

    // Apply spacing and appearance on EVERY render
    label.style.cssText = isShorts
        ? `
            display: block !important;
            margin-top: 4px !important;
            margin-left: 0 !important;
            font-family: "Roboto", Arial, sans-serif !important;
            font-size: 12px !important;
            font-weight: 500 !important;
            color: inherit !important;
            white-space: nowrap !important;
            pointer-events: none !important;
            flex-shrink: 0 !important;
            line-height: 1 !important;
          `
        : `
            display: inline-flex !important;
            align-items: center !important;
            margin-left: 12px !important;
            margin-right: 0 !important;
            margin-top: 0 !important;
            vertical-align: middle !important;
            line-height: normal !important;
            opacity: 1 !important;
            visibility: visible !important;
            font-family: "Roboto", Arial, sans-serif !important;
            font-size: 14px !important;
            font-weight: 500 !important;
            color: inherit !important;
            white-space: nowrap !important;
            pointer-events: none !important;
            flex-shrink: 0 !important;
          `;

    forceVisibility(btn);
    // console.log(`YTT: [Dislike] Rendered ${countText} for video ${videoId}`);
    
    setupObserver();
}

function setupObserver() {
    if (globalObserver) return;
    
    globalObserver = new MutationObserver((mutations) => {
        const isSelfMutation = mutations.every(m => {
            const target = m.target;
            return target.nodeType === 1 && (
                target.classList.contains("ytt-hijacked-label") || 
                target.closest?.(".ytt-hijacked-label")
            );
        });

        if (!isSelfMutation) {
            tryRenderDislike();
        }
    });

    globalObserver.observe(document.documentElement, { childList: true, subtree: true });
}

function applyDislikeCountState() {
    if (dislikeCountSettings.enabled) {
        tryRenderDislike();
    } else {
        removeDislikeCount();
    }
}

function removeDislikeCount() {
    const labels = document.querySelectorAll(".ytt-hijacked-label");
    labels.forEach(l => l.remove());
    if (globalObserver) {
        globalObserver.disconnect();
        globalObserver = null;
    }
}


